import{a as e,i as t,r as n,t as r}from"./app-BZ0-Uw4U.js";var i=JSON.parse(`{"path":"/blogs/magento2-multi-vendor-marketplace.html","title":"User Guide for Adobe Commerce Multi Vendor Extension","lang":"en-US","frontmatter":{},"git":{"updatedTime":1781706203000,"contributors":[{"name":"Mohd Munassir Alam","username":"","email":"munassir.alam632@webkul.in","commits":2},{"name":"Cursor","username":"Cursor","email":"cursoragent@cursor.com","commits":1,"url":"https://github.com/Cursor"}],"changelog":[{"hash":"fec0b4ca4a2ac9add31ec0545055b0e7503c7108","time":1781706203000,"email":"munassir.alam632@webkul.in","author":"Mohd Munassir Alam","message":"Updated Blog MD files"},{"hash":"7f690eb6836c870c0b97ce711d51fcb9cd13c124","time":1781695993000,"email":"munassir.alam632@webkul.in","author":"Mohd Munassir Alam","message":"Add Webkul Magento 2 documentation site with VuePress.","coAuthors":[{"name":"Cursor","email":"cursoragent@cursor.com"}]}]},"filePathRelative":"blogs/magento2-multi-vendor-marketplace.md"}`),a={name:`magento2-multi-vendor-marketplace.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="user-guide-for-adobe-commerce-multi-vendor-extension" tabindex="-1"><a class="header-anchor" href="#user-guide-for-adobe-commerce-multi-vendor-extension"><span>User Guide for Adobe Commerce Multi Vendor Extension</span></a></h1><p>Updated 7 May 2026</p><p><a href="https://magento2demo.webkul.in/marketplace/" target="_blank" rel="noopener noreferrer">Live Demo</a></p><p><a href="https://store.webkul.com/magento2-multi-vendor-marketplace.html" target="_blank" rel="noopener noreferrer">Magento 2 Multi Vendor Extension</a> provides a platform where multiple sellers (vendors) can register to marketplace, list, and sell their products or services to customers.</p><p>Adobe Commerce Marketplace Extension converts your online store into a complete online marketplace shop.</p><p>Therefore, using Magento 2(Adobe Commerce) Marketplace Extension, the seller can manage the inventory, shipment, Seller Profile page, Seller Collection page, and much more.</p><p>The seller can add multiple product types like Simple, Configurable, Virtual &amp; Downloadable.</p><p>Furthermore, Magento 2 Marketplace Plugin supports all the Magento 2 templates and themes and it is compatible with RWD (<a href="https://webkul.com/website-development/" target="_blank" rel="noopener noreferrer">responsive web designs</a>).</p><p>If you’re looking to make your customers as resellers on your Magento 2 store, then you can check<a href="https://store.webkul.com/magento2-reseller-extension.html" target="_blank" rel="noopener noreferrer"> Magento 2 Reseller Extension</a></p><p>**Important Notes:\xA0**</p><ol><li>If you’re using Magento version 2.3.0-2.3.3, then please install the Patch file v2.3.0-2.3.3 available in the Magento 2 Marketplace plugin zip.</li><li>There is no need to install the patch for versions above Magento v2.3.3.</li><li>The greater version of the Marketplace Extension will not work with the lower version of Magento.</li><li>If you have Magento 2.0.x then you can use a lower version of the Marketplace.</li><li>The Multi-Vendor Marketplace version 2.0.1 will not work with the Magento 2.0.x version, it will work with Magento 2.1.x.</li><li>To manage the Multi-Source Inventory feature at the sellers’ end. You must have installed Marketplace MSI for Magento 2.</li></ol><p>Watch below video tutorials to understand Multi Vendor Marketplace Extension workflow:</p><p>Video tutorial #1</p><p>ekuRTIdBjeA</p><p>Video Tutorial #2</p><p>lqrw7X0GVMQ</p><p>Video Tutorial #3</p><p>XK61MNwvj2o</p><p>Video tutorial #4</p><p>ed1sEshDRa8</p><p>Video tutorial #5</p><p>BFYiIryG3CU</p><p>Video tutorial #6</p><p>6pgm3mmfTHs</p><p>Video tutorial #7</p><p>42IQRemensI</p><p>Video tutorial #8</p><p>RtrlyPcm6cE</p><h2 id="features-of-magento-2-marketplace-extension" tabindex="-1"><a class="header-anchor" href="#features-of-magento-2-marketplace-extension"><span>Features of Magento 2 Marketplace Extension</span></a></h2><ul><li>Magento 2 multi vendor module is compatible with the Hyva Theme.</li></ul><p><strong>Note:</strong> Hyva module currently supports only the default vendor dashboard.</p><h3 id="advance-admin-end-features" tabindex="-1"><a class="header-anchor" href="#advance-admin-end-features"><span>Advance Admin End Features</span></a></h3><ul><li><p>Easy configuration of the Marketplace Module.</p></li><li><p>Also, magento 2 multi vendor module offers an Attractive design for managing the Products, Sellers, and commissions.</p></li><li><p>Additionally, this module provides an option to view the list of all the sellers in the marketplace in one place.</p></li><li><p>Furthermore, the admin can set the status of the seller profiles as Approve/Disapprove/Deny/Processing</p></li><li><p>Even, the admin can allow a separate vendor dashboard.</p></li><li><p>Admin can manage the Seller profile page setting.</p></li><li><p>Admin can assign a category and subcategory to the seller.</p></li><li><p>Further, the Admin can view, approve, disapprove, update, deny, and delete a seller-requested product.</p></li><li><p>Admin can enable/disable minimum order functionality.</p></li><li><p>Admin can set minimum order amount.</p></li><li><p>The admin can Inline edit the products in the admin end grid.</p></li><li><p>Admin can send global news to sellers.</p></li><li><p>Admin can manage the fulfillment label, text and image.</p></li></ul><h3 id="other-features-of-admin-end" tabindex="-1"><a class="header-anchor" href="#other-features-of-admin-end"><span>Other Features of Admin End</span></a></h3><ul><li>Additionally, the admin can view the list of unapproved seller products.</li><li>Plus, the admin can approve mass products and sellers at a time.</li><li>The Admin can allow a seller to add a product limit for a customer on product purchases.</li><li>Furthermore, the admin can allow a seller to add related products, up-sell products, and cross-sell products from the seller’s panel.</li><li>Plus, the seller gets a mail notification when product inventory reaches the specified minimum level set with the admin.</li><li>Also, the seller can view hints for fields if enabled and the admin can set them.</li><li>Configuration setting for SKU prefix that the admin can configure for seller’s products.</li><li>In addition, the admin can view notifications for seller requests, seller products, and feedback reviews.</li><li>The admin can create email custom templates too.</li><li>Admin can choose and customize between three different layouts for Landing Page as well.</li><li>Also, the admin can configure marketplace landing page options like- banner, banner content, button label, icons, etc</li><li>In addition, the admin can choose to auto-approve orders or not.</li><li>Also, the admin can view the Product Preview for product approval.</li><li>The admin can enable/disable separate dashboard seller wise.</li><li>Additionally, features a Product Assignment tab to render the product grid to mass assign products to the seller in the seller edit page in the admin panel.</li><li>Make SKU configurable Static/Dynamic for seller’s products so that admin can set accordingly.</li><li>Admin can now refine the search process of enabling the seller filter in layer navigation.</li><li>The Admin can do TAX management for the seller’s product.</li><li>The admin can use Google Analytics to analyze website data.</li></ul><h3 id="seller-end-key-features" tabindex="-1"><a class="header-anchor" href="#seller-end-key-features"><span>Seller End Key Features</span></a></h3><ul><li>An interactive vendor dashboard in a separate vendor panel.</li><li>Separate Seller Profile with Company Logo and Seller Collection Page with Company Banner.</li><li>The seller can delete his logo and banner from the seller’s profile</li><li>Vendors can access their customer grid, reviews, and activities quickly.</li><li>Additionally, this module offers a different Product type for Seller (Simple, Downloadable, Virtual, Configurable).</li><li>Also, allows the seller to add/update/delete products from their dashboard</li><li>Mass delete of product in seller’s product list.</li><li>So, using a dashboard seller can track his income, latest order, comment and reviews, recent orders, and recent comments with the total sales matrix.</li><li>In addition, allow vendors to make a withdrawal request to the admin for their remaining amount via a separate vendor panel.</li><li>Additionally, this module provides an attractive landing page with top 4 sellers with their top 3 products too.</li><li>The marketplace sells page (in the case of layout 2 and layout 3) works as seller central where a seller can separately create his account.</li><li>Furthermore, allow the seller to edit the shop URL for the Profile page, collection page, review page, and Location page.</li><li>Sellers can add social media icons on their profile pages as well.</li><li>The module uses Ajax checks for vendor/seller shop URLs.</li><li>Magento 2 multi vendor module provides a captcha security feature so that customers can contact sellers. customer can give their reviews.</li><li>The module allows sellers to inline edit products in the seller end grid.</li><li>The plugin allows the seller to create a partial shipment and partial invoice for his orders.</li><li>The module allows the seller to add/edit/delete configurable product attributes.</li><li>Sellers can now filter products and orders from general filters provided on top of grid listing.</li><li>Sellers will get low-stock notifications.</li><li>Seller can now add draft products.</li><li>Seller can manage fulfillment label, text and image.</li></ul><h3 id="other-seller-end-key-features" tabindex="-1"><a class="header-anchor" href="#other-seller-end-key-features"><span>Other Seller End Key Features</span></a></h3><ul><li>Different seller commissions for every seller.</li><li>Display total Payout and remaining amount of seller’s in the seller’s dashboard</li><li>Separate seller’s product collection.</li><li>Also, the sellers can get low stock notifications when the admin will enable the option.</li><li>A seller can manage the order from the front end that will be approved from the admin end.</li><li>The seller can set the minimum order amount.</li><li>Seller profile link for each item on the customer order view page.</li><li>Also, the seller can use Google Analytics to analyze website data.</li></ul><h3 id="additional-features-of-seller-end" tabindex="-1"><a class="header-anchor" href="#additional-features-of-seller-end"><span>Additional Features of Seller End</span></a></h3><ul><li>Additionally, the sellers can view notifications for product approval, new orders, and new transactions.</li><li>Tax/VAT information for the seller profile page can be given.</li><li>The seller can change their profile page background color too.</li><li>The seller can add a Return and Shipping policy when the admin will enable it.</li><li>Allow sellers to add Carrier and Tracking numbers for orders.</li><li>A vendor can create a duplicate copy of a product listing.</li><li>Product filter by name, date, and status in the seller’s product list</li><li>The Admin can see the seller’s transaction details of the total payout from the admin panel.</li><li>The seller can view the total earnings of his store Day, Month &amp; Year-wise with the help of a vivid sale vs period (Day, Month &amp; Year) graph.</li><li>Allow vendors to add information store-wise.</li><li>Automatically generate seller product URLs like- Profile, Collection, Location &amp; feedback URL.</li><li>The seller can add a sample URL, link sample URL, and link URL for downloadable products.</li><li>In addition, the sellers can visualize their top-selling category with the help of the Pie chart view.</li><li>Also, display sales reports by using charts, sales by location, and sales stats, and filter the reports by year, month, week, and day in the seller dashboard.</li><li>Moreover, customers can view all the details about the product given by the seller.</li><li>Even, sellers can refund their order with return quantity to stock option and add comment option</li><li>Option to configure products with available attributes-key features.</li><li>Add Videos along with your product images at the add new product page in the Marketplace.</li><li>Public pages of sellers are SEO friendly too.</li><li>Also, the seller’s order can be filtered by order id, date, and status in the seller’s order history page.</li><li>Seller’s transaction report with download record in CSV and search filter by transaction id and date too.</li></ul><h3 id="customer-end-features" tabindex="-1"><a class="header-anchor" href="#customer-end-features"><span>Customer End Features</span></a></h3><ul><li>Customers will do shopping from the variety of product options available.</li><li>In addition, customers can search sellers by seller shop name on the seller list page</li><li>The customers can compare the products based on price, vendor rating, and location too.</li><li>Also, customers can give product ratings and reviews.</li><li>Additionally, the customers can also view the rating of the seller.</li><li>Moreover, the customers can view all the details about the product given by the seller.</li><li>Plus, the customer can contact the seller with captcha support as well.</li><li>Furthermore, customers can also compare the price of the products of different sellers.</li><li>The customers can view the seller profile page as well.</li><li>In addition, the customer can place an order of different seller products by using the same cart.</li><li>Also, a customer can send a request to the admin to become a marketplace seller</li><li>Even, a customer can check out at once having multiple sellers’ products in the shopping cart.</li></ul><h2 id="installation-of-magento-2-marketplace-extension" tabindex="-1"><a class="header-anchor" href="#installation-of-magento-2-marketplace-extension"><span>**Installation of Magento 2 Marketplace Extension</span></a></h2><p>The installation is quite simple just like the standard\xA0<a href="https://store.webkul.com/Magento-2.html" target="_blank" rel="noopener noreferrer">Magento 2 extensions</a>.</p><h3 id="download-module" tabindex="-1"><a class="header-anchor" href="#download-module"><span>#Download Module</span></a></h3><p>Firstly, you need to log in to the <a href="https://store.webkul.com/" target="_blank" rel="noopener noreferrer">Webkul Store,</a> go to <strong>My Account&gt;My Purchased Products section,</strong> verify, and then download and extract the contents of this zip folder on the system.</p><h3 id="upload-folder" tabindex="-1"><a class="header-anchor" href="#upload-folder"><span>#Upload Folder</span></a></h3><p>When the module zip extracts, follow path src&gt;app and then copy the app folder into the Magento 2 root directory on the server as shown below:</p><p><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2016/09/Move-app-folder-2.png" target="_blank" rel="noopener noreferrer">![Magento 2 Marketplace Extension](https://cdnblog.webkul.com/blog/wp-content/uploads/2016/09/Move-app-folder-2.png)</a></p><h3 id="run-commands" tabindex="-1"><a class="header-anchor" href="#run-commands"><span># Run Commands</span></a></h3><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">php bin/magento setup:upgrade</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">php bin/magento setup:di:compile</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">php bin/magento setup:static-content:deploy</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">php bin/magento indexer:reindex</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">php bin/magento cache:flush</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>Run below mentioned commands to start admin news related messages.</p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">php bin/magento queue:consumers:start admin.news.published &amp;</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>Run below mentioned commands to start low stock seller’s products related messages.</p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">php bin/magento queue:consumers:start seller.product.lowstock &amp;</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h2 id="configuration-for-multi-lingual-support" tabindex="-1"><a class="header-anchor" href="#configuration-for-multi-lingual-support"><span>Configuration for Multi-lingual Support</span></a></h2><p>In addition, for <strong>multilingual</strong> support, the\xA0admin will navigate through **Store &gt; Configuration &gt; General &gt; Locale Options.\xA0**</p><p>Furthermore, select the <strong>locale</strong> as German (the language into which admin wants to translate his store content).</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/Locale-options.webp" alt="Locale options
"></p><h2 id="magento-2-multi-vendor-extension-translation" tabindex="-1"><a class="header-anchor" href="#magento-2-multi-vendor-extension-translation"><span>Magento 2 Multi Vendor Extension Translation</span></a></h2><p>For translating the module language, navigate through\xA0<strong>src/app/code/Webkul/Marketplace/i18n</strong>\xA0and edit the en_US.csv file.</p><p>Thereafter, rename the CSV as “en_SA.csv” and translate all right side content after the comma in the Arabic language. After editing the CSV, save it.</p><p>Now, they have to open the file named <strong>en_US.CSV</strong> for editing.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/04/Language1-DP-.webp" alt="translation"></p><p>Now, upload it to the path\xA0<strong>src/app/code/Webkul/Marketplace /i18n</strong>\xA0where the installation of Magento 2 is on the server.</p><p>The module translates into the Arabic Language. It supports both RTL and LTR languages.</p><p>The user can edit the CSV like the image below.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/code-1.webp" alt="language-translation"></p><p>Thus, the language translation completes.</p><h2 id="arabic-translation-–-magento-2-marketplace-extension" tabindex="-1"><a class="header-anchor" href="#arabic-translation-–-magento-2-marketplace-extension"><span>Arabic Translation – Magento 2 Marketplace Extension</span></a></h2><h3 id="step-1" tabindex="-1"><a class="header-anchor" href="#step-1"><span><strong>Step 1:</strong></span></a></h3><p>So, most importantly, If a user wants to translate their module from <strong>English</strong>\xA0into the\xA0<strong>Arabic</strong> language.</p><p>Then they need to follow the path <em><strong>app/code/Webkul/Marketplace/i18n</strong></em> in their unzipp Magento Marketplace folder.</p><p>Forthwith, here the user will get a <strong>CSV</strong> file with the name “<strong>en_US.csv</strong>” as shown below in the snapshot.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/1-3-4-1200x523.webp" alt="Arabic language translation 1
"></p><h3 id="step-2" tabindex="-1"><a class="header-anchor" href="#step-2"><span><strong>Step 2:</strong></span></a></h3><p>Straightaway just renames this <strong>en_US.csv</strong>\xA0 to “<strong>ar_SA.csv</strong>” as shown below in the snapshot.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/2-3-3-1200x529.webp" alt="Arabic language translation 2
"></p><h3 id="step-3" tabindex="-1"><a class="header-anchor" href="#step-3"><span><strong>Step 3:</strong></span></a></h3><p>Moreover, right-click on this ** rename CSV file** and click the <strong>edit</strong> button to <strong>translate all right side content</strong> of this <strong>CSV</strong> after the\xA0comma **into the\xA0Arabic language.\xA0**</p><p>Now, see the actual <strong>CSV file</strong> after opening it up <strong>:</strong></p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/code-2.webp" alt="arabic languauge"></p><p>Even the users can <strong>edit the CSV</strong> as per the below screenshot:</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/5-1-7.webp" alt="arabic translation"></p><h3 id="step-4" tabindex="-1"><a class="header-anchor" href="#step-4"><span><strong>Step 4:</strong></span></a></h3><p>Now after translating the content of the CSV ** save it** and then <strong>upload it</strong> to the path ***app/code/Webkul/Marketplace/i18n.\xA0*** Where you have installed the <strong>Magento 2 on the server</strong>.</p><p>Then, the module gets ** translate into the Arabic Language**.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/3-3-2-1200x538.webp" alt="language translation - 5"></p><h2 id="how-to-get-google-analytics-tracking-id" tabindex="-1"><a class="header-anchor" href="#how-to-get-google-analytics-tracking-id"><span>How to get Google Analytics Tracking ID</span></a></h2><p>To get the google analytics ID, the user will need to get the <a href="https://www.google.com/analytics/" target="_blank" rel="noopener noreferrer">Google Analytics Account first</a>. Here, the user can click on the Sign in to Analytics or Start for free if don’t have an analytics account.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/create-account-google-analytics.png" alt="Multi Vendor- create-account-google-analytics"></p><p>Now click on the Start for free to create a google analytics account.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/2-12.png" alt="multi vendor - create or signin google account"></p><p>Now, sign in using the google account to create and set up analytics properties. Thus a welcome message will display to the user. Now click on the Start measuring.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/3-7.png" alt="multi vendor - welcome message"></p><h3 id="additional-details" tabindex="-1"><a class="header-anchor" href="#additional-details"><span>Additional Details</span></a></h3><p>Now enter the further required details to continue.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/4-6.png" alt="multi vendor - enter the required details"></p><p>So, after entering the required details click on the Next button.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/5-6.png" alt="multi vendor - google analytics"></p><p>Now, enter the property name, and select the reporting time zone, and currency.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/6-4.png" alt="6-4"></p><p>Now click on the Show advance options to create a Universal Analytics property. You can select as per your convenience, but we have selected Create a Universal Analytics property only.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/7-3.png" alt="multi vendor select the required data"></p><p>Now, select from the available options and click on the Create button.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/8-4.png" alt="multi vendor - universal tracking "></p><h3 id="terms-and-conditions" tabindex="-1"><a class="header-anchor" href="#terms-and-conditions"><span>Terms and conditions</span></a></h3><p>Accept the terms &amp; conditions and process further.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/9-5.png" alt="multi vendor - accept terms and conditions"></p><p>Now select the events for which you want to receive the email notifications from Google and click on the Save button.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/10-4.png" alt="multi vendor - email notification"></p><p>Thus,\xA0you can simply copy the Tracking ID from the screen and paste it into the module configuration.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/11-3.png" alt="multi vendor - enter analytics tracking ID"></p><h2 id="magento-2-marketplace-extension-configuration" tabindex="-1"><a class="header-anchor" href="#magento-2-marketplace-extension-configuration"><span>Magento 2 Marketplace Extension Configuration</span></a></h2><p>Afterward the successful installation of the Magento 2(Adobe Commerce) Marketplace Extension, the admin is able to view the marketplace configuration setting under <strong>Store &gt; Configuration &gt; Marketplace</strong>.</p><p>Let us explain the importance of all the fields one by one-</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/Config-General-settings-1.webp" alt="Configuration settings "></p><h3 id="general-settings-–-magento-2-multi-vendor-extension" tabindex="-1"><a class="header-anchor" href="#general-settings-–-magento-2-multi-vendor-extension"><span>General Settings – Magento 2 Multi Vendor Extension</span></a></h3><p>Here, the admin can set –</p><ul><li>Admin Name – Firstly the admin needs to enter his name.</li><li>Admin Email-ID – After that In this field, the admin will enter their email address.</li><li>Global Commission Rate – Then, in the global commission, the admin needs to enter a global commission rate in percentage, this commission mechanism is applicable to all the sellers.</li></ul><p>Additionally, let us say as an example there is a seller S1 and his/her product(P1) price is 100 USD.</p><p>So on the sale of product P1 seller will get 80 USD and the admin will get 20 USD as commission if the commission is configured as 20%.</p><ul><li>Deduct Discount Amount From – With this feature the admin can set the deduction of the discount amount, whether it will be deducted from the seller’s total amount or admin commission amount, or both.</li><li>Allow Seller to Manage Orders – By enabling “YES”, the admin allows the sellers to manage the orders from the front end.</li></ul><p>Now, the seller can generate invoices for their order products, generate a tracking number, and shipment for the orders of their products.</p><p>In addition,\xA0 the seller can notify the customers by sending them emails, cancel/refund the order, and even print the order.</p><ul><li>Move Product Tax to Seller Account – Thus, most importantly, If this option is disabled then, the product Tax amount will forward into the Admin account otherwise, it will go into the Seller account.</li><li>Seller Approval Required – Likewise, partner or seller approval is the same as product approval, during sign-up of the seller if the admin allows this option.</li></ul><p>Furthermore, then the user who will sign up in the store as a seller will convert into the seller automatically. The store owner can set <strong>YES or NO</strong>.</p><h3 id="set-captcha-enable-–" tabindex="-1"><a class="header-anchor" href="#set-captcha-enable-–"><span><strong>Set Captcha Enable</strong> –</span></a></h3><p>If this is set as “Yes” then if any user contacts the seller then on the Contact Form, the additional question appears for the security purpose.</p><p>Furthermore, if the option is set as “No” then the customer can contact the sellers without any additional security questions.</p><ul><li>Allow Seller for Google Analytics –\xA0The admin can select “Yes” to let the seller use google analytics.</li></ul><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/Config-General-settings-2.webp" alt="Config- General settings 2"></p><p><strong>Fulfillment Settings</strong> –</p><ul><li>Image – Upload the image by selecting them and will be shown on product page which will be fulfill by admin.</li><li>Label – Write the name and will be used to show in fulfillment label at admin and seller product edit page.</li><li>Text – Write a text and will shown on product page.</li></ul><p>Fulfillment settings also manage by the seller in their marketplace edit profile section as shown in below image:</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/2vendor-account-settings-edited.webp" alt="fulfilllment"></p><p>The Fulfillment option is also visible at frontend and specifies the fulfillment of this product as shown in image below:</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/seller-fulfillment.webp" alt="seller-fulfillment"></p><h2 id="manage-google-analytics-–-magento-2-marketplace-extension" tabindex="-1"><a class="header-anchor" href="#manage-google-analytics-–-magento-2-marketplace-extension"><span>Manage Google Analytics – Magento 2 Marketplace Extension</span></a></h2><p>The admin can navigate to the **Store&gt;Configuration&gt;Sale&gt;Google API, **enable the module and\xA0enter the Analytics Tracking ID here in the Account Number.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/Google-analytics.webp" alt="Google analytics configuration "></p><h2 id="allow-seller-separate-dashboard-marketplace-extension" tabindex="-1"><a class="header-anchor" href="#allow-seller-separate-dashboard-marketplace-extension"><span>Allow Seller Separate Dashboard: Marketplace Extension</span></a></h2><p>Also, the admin can allow the <strong>vendors to have a separate dashboard</strong> in the ** Magento 2 Multi Vendor Extension**.</p><p>The admin selects this option as “Yes”, as a vendor is also a customer, the vendors are able to have a separate dashboard.</p><p>That will not have the account section for the customer however only the vendor dashboard.</p><p>Now, the Admin can also upload a logo for the ** Seller’s Separate Dashboard** which is visible on the upper left of the <strong>Separate Vendor Panel View</strong>.</p><p>Therefore, set up this option the admin will navigate to <strong>Stores</strong> &gt; <strong>Configuration</strong> &gt; <strong>Webkul</strong> &gt; <strong>Marketplace</strong> &gt; <strong>Seller Dashboard Layout Setting</strong>.</p><h4 id="minimum-order-amount-settings" tabindex="-1"><a class="header-anchor" href="#minimum-order-amount-settings"><span>Minimum Order Amount Settings</span></a></h4><p>This section allows the admin to set the minimum order amount to be applicable to the customers.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/Minimum-order-amount-settings-1200x493.webp" alt="Minimum order amount settings
"></p><ul><li>Enable –\xA0Enable this feature for the marketplace store.</li><li>Minimum Amount –\xA0Now define the minimum order amount.</li><li>Amount Value for Sellers –\xA0if this value is yes then the amount value will be used for those sellers who have not filled the minimum order amount.</li></ul><h4 id="seller-dashboard-layout-settings" tabindex="-1"><a class="header-anchor" href="#seller-dashboard-layout-settings"><span>Seller Dashboard Layout Settings</span></a></h4><p>Here, the admin will select the option “<strong>Allow Seller Separate dashboard</strong>” and set it to “Yes”.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/Seller-dashboard-layout-settings.webp" alt="Seller dashboard layout settings"></p><p>So, below find the comparison wherein we are going to show you the changes that take effect after the admin sets this setting “<strong>Allow seller separate dashboard</strong>” as “<strong>Yes</strong>” &amp; “No”</p><h3 id="when-the-option-is-set-to-no" tabindex="-1"><a class="header-anchor" href="#when-the-option-is-set-to-no"><span>When the option is set to No</span></a></h3><p>Furthermore, when the option is set to “<strong>No</strong>” which is the default one. In this case, the vendor’s account will have the **vendor **and **customer panel\xA0**both.</p><p>Both the panel is displayed as per the below image.</p><h4 id="vendor-dashboard" tabindex="-1"><a class="header-anchor" href="#vendor-dashboard"><span>Vendor Dashboard</span></a></h4><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/mp-dashboard-1-edited.webp" alt="MP daahboard"></p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/06/marketplace-vendor-dashboard-reports-2.webp" alt="marketplace-vendor-dashboard-reports"></p><h3 id="separate-seller-panel-–-magento-2-marketplace-extension" tabindex="-1"><a class="header-anchor" href="#separate-seller-panel-–-magento-2-marketplace-extension"><span>Separate Seller Panel – Magento 2 Marketplace Extension</span></a></h3><p>Now, if the admin sets the setting “<strong>Allow seller separate dashboard</strong>” as “<strong>Yes</strong>“. Then, in this case, also the vendor and customer panel will have separate dashboards.</p><p>Hence, both panels will no longer be visible on the same dashboard.</p><p>Therefore for the vendor panel, the vendor needs to log into his vendor account. And for the customer panel, he needs to log in to the customer account separately as per the below image.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/vendor-separate-dashboard-1200x541.webp" alt="vendor dashboard
"></p><p>Furthermore, by clicking the <strong>Vendor Login</strong> link, the seller is able to see the new login section and can enter his credentials to log in to his account panel.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/Vendor-separate-login-1200x796.webp" alt="vendor login"></p><p>After <strong>login</strong>, the <strong>vendor dashboard</strong>\xA0will appear as shown in the below snapshot.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/Vendor-separate-dashboard-1-edited.webp" alt="vendor separate dashboard"></p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/06/marketplace-separate-dashboard-reports-901x1024.webp" alt="marketplace-vendor-dashboard-activity"></p><p>So, let’s go through the <strong>various options</strong> that are available on the above page.</p><h3 id="vendor-account-drop-down" tabindex="-1"><a class="header-anchor" href="#vendor-account-drop-down"><span><strong>Vendor Account Drop-Down</strong></span></a></h3><p>Therefore, after clicking on the vendor account drop-down option will show the account related options which include –</p><ul><li>Account Settings</li><li>Buyer Dashboard</li><li>Logout</li></ul><h3 id="account-settings" tabindex="-1"><a class="header-anchor" href="#account-settings"><span><strong>Account Settings</strong></span></a></h3><p>In addition, clicking the account settings menu option will redirect the vendor to the ** marketplace edit seller profile** page.</p><p>Now, the vendor can edit his profile information and view his collection and profile pages by clicking the buttons provided.</p><p>Additionally, on this page, the vendor can manage his payment information, google analytics, and much more.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/1-vendor-account-settings.webp" alt="vendor account settings - 1
"></p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/2-vendor-account-settings.webp" alt="vendor account settings - 2"></p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/3-vendor-account-settings.webp" alt="vendor account - 3"></p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/4-vendor-account-settings.webp" alt="vendor account - 4"></p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/5-vendor-accounts-settings.webp" alt="vendor account - 5"></p><h3 id="vendor-dashboard-–-magento-2-marketplace-extension" tabindex="-1"><a class="header-anchor" href="#vendor-dashboard-–-magento-2-marketplace-extension"><span><strong>Vendor Dashboard – Magento 2 Marketplace Extension</strong></span></a></h3><p>Therefore after clicking the <strong>Vendor****Dashboard</strong> menu option, the vendor will switch to his buyer account panel page.</p><p>Here, the vendor can see his buyer account panel and the various other options related to it.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/buyer-dashboard-edited.webp" alt="buyer dashboard"></p><p>Furthermore, in the Buyer dashboard, the user can see the <strong>Vendor Dashboard</strong> option. Further, by clicking the <strong>Vendor Dashboard</strong> menu option, the user will switch back to his vendor account panel page.</p><h3 id="sign-out" tabindex="-1"><a class="header-anchor" href="#sign-out"><span><strong>Sign Out</strong></span></a></h3><p>Therefore, most importantly, after clicking on the <strong>sign-out</strong> button will log out the vendor from his account panel and redirect the vendor to the store home page.</p><h3 id="seller-notifications-–-magento-2-marketplace-extension" tabindex="-1"><a class="header-anchor" href="#seller-notifications-–-magento-2-marketplace-extension"><span><strong>Seller Notifications – Magento 2 Marketplace Extension</strong></span></a></h3><p>Consequently, clicking the notification icon will show the recent notifications for the:</p><ul><li>Orders(Place Order by customer/after the admin approves an order),</li><li>Products(add/approve by the admin),</li><li>Transactions(when the admin makes a payout to the seller), and</li><li>Feedback(After the approval of seller feedback by the admin).</li></ul><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/vendor-notification-list--1200x500.webp" alt="notification"></p><p>Thereafter, clicking the “<strong>View All</strong>” option on the notification panel will redirect you to the grid view of the notifications.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/vendor-notification-1200x415.webp" alt="list of notification"></p><h3 id="home-icon-–-magento-2-marketplace-extension" tabindex="-1"><a class="header-anchor" href="#home-icon-–-magento-2-marketplace-extension"><span>Home Icon – Magento 2 Marketplace Extension</span></a></h3><p>After clicking the <strong>home icon</strong> will redirect the vendor to the home page as shown below in the snapshot.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/Vendor-separate-dashboard-3-edited.webp" alt="vendor home icon"></p><h3 id="vendor-side-–-panel-account-option" tabindex="-1"><a class="header-anchor" href="#vendor-side-–-panel-account-option"><span>Vendor Side – Panel account option</span></a></h3><h4 id="dashboard" tabindex="-1"><a class="header-anchor" href="#dashboard"><span><strong>Dashboard</strong></span></a></h4><p>After clicking on the dashboard, the vendor can see the complete statistics for his store account. The vendor can see the –</p><ul><li>Pending orders quantity</li><li>Number of orders in process</li><li>Complete orders quantity</li></ul><p>Moreover, the vendor can also see the following details:</p><ul><li>Total number of orders that have been placed by the customers</li><li>The total number of products available,</li><li>The total number of logged-in customers,</li><li>The lifetime sales and the total payout that is made by the admin to the vendor.</li></ul><p>Now, the seller can also find the details of the latest orders that have been placed by the customers.</p><h4 id="orders" tabindex="-1"><a class="header-anchor" href="#orders"><span><strong>Orders</strong></span></a></h4><p>Now, clicking the <strong>Orders</strong> menu option will bring up the section to view all the orders that have been placed for this vendor’s products.</p><p>Here, the UI components have been used to display the grid that uses Ajax to display the grid data.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/vendor-print-slip.webp" alt="vendor print slip"></p><p>Clicking the “<strong>Order</strong>” link under the column **View **will allow the seller to view the complete order details.</p><p>in short, the seller can then accordingly generate the shipments, invoice, send emails to customers,cancel the order and print the order details.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/vendor-manage-order-1.webp" alt="vendor manage order"></p><h3 id="products" tabindex="-1"><a class="header-anchor" href="#products"><span>Products</span></a></h3><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/vendor-add-product.webp" alt="vendor add product"></p><ul><li>Taping the Add Products menu option brings up the section to add the products. from here the seller can easily add in his products.</li></ul><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/vendor-add-product-simple-edited.webp" alt="vendor add product
"></p><ul><li>Here, the seller can easily add their product. After filling the details they need to click on save.</li><li>When the seller click on draft, It adds their products as a draft, it will not visible on frontend. Draft product are those product that are saved but not yet published.</li></ul><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/06/add-draft-product-1.webp" alt="add draft product at seller end"></p><h4 id="draft-products" tabindex="-1"><a class="header-anchor" href="#draft-products"><span>Draft Products</span></a></h4><ul><li>You can check the draft product list by navigating through Products&gt; Draft products.</li></ul><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/06/draft-product-visible-1.webp" alt="draft product visible"></p><ul><li>Hence, under the My product List, the seller will find all of his products.\xA0 Here, the UI components have been used to display the grid that uses ajax to display the grid data.</li><li>In the product list, you will get options for manage the products – Enabled products, disabled products, low stock. out of stock, pending products,denied products by admin.</li><li>Quantity Sold:\xA0 The quantity/number of Products sold by the seller.</li><li>Visibility :\xA0It shows where the product will be visible.</li><li>Quantity Confirmed: It confirms that the quantity of the product order has been received and accepted.</li><li>Quantity Pending: If the quantity status is “Pending,” your order has been received by the seller, but your payment has not yet been processed.</li></ul><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/MP-product-list.webp" alt="product list"></p><ul><li>Here, when seller click on edit, You can edit your product as shown in image below.</li><li>While editing a product, If the fulfillment checkbox is enabled, then the fulfillment will be done by the admin. If disabled, fulfill by the respective seller as show in image below –</li></ul><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/06/fulfillment-1.webp" alt="marketplace fulfillment by seller"></p><ul><li>Also, In Marketplace Extension, the seller can add filters according to their product status. The seller can choose a status from the available options.</li><li>the seller can also view the pending products and can see the remarks of products which is given by admin as shown in the image below:</li></ul><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/mp-product-list-2-edited.webp" alt="mp-product-list"></p><ul><li>The seller can also view the denied products as shown in image below:</li></ul><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/denied-product.webp" alt="denied-product"></p><ul><li>Lastly, under the Configurable Attribute menu option, the seller can create the attribute for Configurable Products including Attribute Code, Attribute Label, Catalog Input Type, and Values Required.</li></ul><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/Configurable-products-1200x796.webp" alt="configuarble product"></p><h4 id="customers" tabindex="-1"><a class="header-anchor" href="#customers"><span><strong>Customers</strong></span></a></h4><p>Now, under this section,\xA0 the seller can view all of his customers and can see the order placed by the customers as well.</p><p>Here, the UI components have been used to display the grid that uses ajax to display the grid.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/MP-Customer.webp" alt="MP Customer"></p><h3 id="seller-transactions-–-magento-2-marketplace-extension" tabindex="-1"><a class="header-anchor" href="#seller-transactions-–-magento-2-marketplace-extension"><span><strong>Seller Transactions – Magento 2 Marketplace Extension</strong></span></a></h3><p>Forthwith, under the transactions, the sellers can check their statements (their total earnings) and can make a request for the Withdrawal(for their remaining payout).</p><p>Henceforth, clicking the “<strong>Make a Withdrawal</strong>” button will send an email to the admin that the seller wants to make a withdrawal.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/Transaction-edited.webp" alt="transaction"></p><p>Afterward, by clicking the <strong>View</strong> link the vendor can see the <strong>transaction details</strong> as shown below in the snapshot.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/Tranaction-details-edited.webp" alt="transaction details "></p><h3 id="timely-earnings-report" tabindex="-1"><a class="header-anchor" href="#timely-earnings-report"><span>Timely Earnings Report</span></a></h3><p>Even, the seller can view the earning report of the store in terms of the day, month &amp; year wise.</p><h4 id="day-wise-report" tabindex="-1"><a class="header-anchor" href="#day-wise-report"><span>Day Wise Report</span></a></h4><p>Also, the seller can view the earning report of the store day-wise.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/Earning-890x1024.webp" alt="Earning "></p><p>The seller can select the period as “Day”, and will enter the specific day to day period. A sales vs day-wise graph will show you the sales day-wise.</p><p>In addition, the seller can view the grid view of the total earning day wise.</p><h4 id="month-wise-report" tabindex="-1"><a class="header-anchor" href="#month-wise-report"><span>Month Wise Report</span></a></h4><p>The seller can view the earnings report of the store Month wise.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/Monthly-earnings-987x1024.webp" alt="earning"></p><p>The seller can select the period as “Month”, and will enter the specific starting and ending month period. A sales vs Month wise graph will show you the sales month wise.</p><p>In addition, the seller can view the grid view of the total earning month wise.</p><h4 id="year-wise-report" tabindex="-1"><a class="header-anchor" href="#year-wise-report"><span>Year Wise Report</span></a></h4><p>Most importantly, the seller can view the earnings report of the store Year wise.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/yearly-earning.webp" alt="yearly earning"></p><h3 id="seller-invoice-packing-slip-pdf-header" tabindex="-1"><a class="header-anchor" href="#seller-invoice-packing-slip-pdf-header"><span>**Seller Invoice &amp; Packing Slip PDF Header\xA0**</span></a></h3><p>Under this menu option, the seller can add their Invoice and Packing slip Address/Vat/Tax information and this is visible in the header of the pdf files.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/Manage-print-PDF-header-info.webp" alt="Manage print pdf header info "></p><h3 id="seller-reviews-–-magento-2-marketplace-extension" tabindex="-1"><a class="header-anchor" href="#seller-reviews-–-magento-2-marketplace-extension"><span><strong>Seller Reviews – Magento 2 Marketplace Extension</strong></span></a></h3><p>Also, under this section, the seller can find all the reviews and ratings given by the customers.</p><p>The vendor can check the price, value, and quality ratings along with the feed summary, review, and the customer name with the status of the review as well.</p><p>Here, the UI components have been used to display the grid that uses ajax to display the grid.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/Marketplace-review.webp" alt="mp review"></p><h3 id="admin-news-–-magento-2-marketplace-extension" tabindex="-1"><a class="header-anchor" href="#admin-news-–-magento-2-marketplace-extension"><span>Admin News – Magento 2 Marketplace Extension</span></a></h3><p>Here, The seller will get news for any sale, offer or regarding any updated news.</p><p>These News are managed by admin and show to every seller on their dashboard.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/Admin-news.webp" alt="admin news"></p><h3 id="seller-profile-settings-–-magento-2-marketplace-extension" tabindex="-1"><a class="header-anchor" href="#seller-profile-settings-–-magento-2-marketplace-extension"><span><strong>Seller Profile Settings – Magento 2 Marketplace Extension</strong></span></a></h3><p>After, clicking the <strong>settings</strong> menu option will redirect the vendor to the ** marketplace edit seller profile** page.</p><p>Here, the vendor can edit his profile information and can view his collection and profile pages by clicking the buttons provided for the same.</p><p>Hence, the vendor can manage his payment information on this page as well as much more.</p><h3 id="product-flag-management-magento-2-marketplace-extension" tabindex="-1"><a class="header-anchor" href="#product-flag-management-magento-2-marketplace-extension"><span>Product Flag Management: Magento 2 Marketplace Extension</span></a></h3><p>For managing the <strong>Product Flags</strong> configurations the admin will navigate to <strong>Stores &gt; Configuration &gt; Marketplace &gt;\xA0 Product Flags</strong>.</p><h4 id="define-minimum-order-amount" tabindex="-1"><a class="header-anchor" href="#define-minimum-order-amount"><span>Define Minimum Order Amount</span></a></h4><p>This section allows the sellers with the feature to set the minimum order amount for the customers.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/Minimum-amt-setting.webp" alt="minimum amt setting
"></p><h3 id="minimum-amount-setting-alert-to-customer" tabindex="-1"><a class="header-anchor" href="#minimum-amount-setting-alert-to-customer"><span>Minimum amount setting alert to customer</span></a></h3><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/Product-notification-minimum-amt-edited.webp" alt="minimum amt notify"></p><h3 id="multi-seller-product-checkout-by-customer" tabindex="-1"><a class="header-anchor" href="#multi-seller-product-checkout-by-customer"><span>Multi Seller Product checkout by customer</span></a></h3><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/product-from-diff-store-edited.webp" alt="product from different seller
"></p><h3 id="seller-profile-link-on-order-view-page" tabindex="-1"><a class="header-anchor" href="#seller-profile-link-on-order-view-page"><span>Seller Profile link on order view page</span></a></h3><p>Customers can get the seller’s profile link for each item on the order view page.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/diff-store-order-information-edited.webp" alt="Order information
"></p><h2 id="report-flag-–-marketplace-extension" tabindex="-1"><a class="header-anchor" href="#report-flag-–-marketplace-extension"><span>Report Flag – Marketplace Extension</span></a></h2><p>In addition, with the Multi Vendor Marketplace Extension, the admin will allow the customer to report a flag against the seller and seller’s product too.</p><p>This exactly means that if the customer is having any issues with a particular product or the seller then they can report the flag from the front end itself.</p><h3 id="seller-flag-management" tabindex="-1"><a class="header-anchor" href="#seller-flag-management"><span>Seller Flag Management</span></a></h3><p>Now, for managing the <strong>Seller Flags</strong> configurations the admin will navigate to <strong>Stores &gt; Configuration &gt; Marketplace &gt;\xA0 Seller Flags</strong>.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/seller-flag-config-settings-edited.webp" alt="seller-config-settings
"></p><p>As shown in the above image the admin will have to add the following field:</p><p><strong>Enable: Firstly, t</strong>he admin will enable the seller flag feature.</p><p>**Text: **This text is displayed to the customer on the seller profile page.</p><p>**Guests Can Flag: **Then <strong>, t</strong>he admin will allow the guest users to report a flag against the seller.</p><p>**Reason: **Then **, **This field will show whether the reason is required or not. If this is set to <strong>Yes</strong> then below two fields get visible:</p><ul><li>Accept Other Reasons: Now, if this field is set to yes then the customer will type their own reason otherwise they have to select from the available reasons.</li><li>Other Field’s Placeholder: This field is visible only if the “Accept Other Reasons” field is set to yes. This will be the placeholder for the other reason field.</li></ul><p>**Note:\xA0**If this field is set to ‘Yes, Required’, make sure some reasons are created and enabled. The First 5 reasons will show on the flag creation page.</p><h3 id="seller-flag-reason" tabindex="-1"><a class="header-anchor" href="#seller-flag-reason"><span>Seller Flag Reason</span></a></h3><p>Even, the admin can add multiple reasons for the seller flags which can be selected by the customer while reporting the flag against the seller.</p><p>And, for adding a new Flag reason the admin will navigate to **Marketplace Management &gt; Seller Flag Reason\xA0**as shown in the image below:</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/mp-seller-1200x796.webp" alt="Mp-seller flag
"></p><p>After that, the list of added reasons gets visible to the admin as shown in the image below:</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/seller-flag-reason-list-1200x796.webp" alt="seller flag reason"></p><p>And, for adding more reasons the admin will click on the <strong>New Reason</strong> button. Just after that, the form will appear with the details like:</p><p>**Flag Reason: **The new reason will display at the front end.</p><p>**Status: **The admin will set the status as enable to show it in the front end.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/seller-new-reason-edited.webp" alt="seller new reason "></p><p>Once the reason is added the admin click on the <strong>Save</strong> button.</p><h3 id="customer-reports-flag-for-the-seller" tabindex="-1"><a class="header-anchor" href="#customer-reports-flag-for-the-seller"><span>Customer Reports Flag for the Seller</span></a></h3><p>As a result, after the backend configurations, the customer can now report a flag against the seller by clicking on the <strong>seller’s store</strong> name on the product page.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/product-sell-by-store-edited.webp" alt="product-sell-by-store
"></p><p>Now, this will take the customer to the seller’s profile page. There the customer will see the Report Seller button just below the store name as shown in the image below:</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/report-seller-daskboard.webp" alt="report-seller
"></p><p>Then, after clicking on the Report Seller, the customer will provide the report details. Details are the same for registered and guest customers.</p><p>**Note:\xA0**For the registered customers the Name and Email fields get Auto-filled and Non-Editable. Whereas, for the guest customers the same is Unfilled and Editable.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/fill-details-report-customer.webp" alt="fill-details-seller
"></p><p>After Submitting the form the details are visible to the admin at the backend. For this, the admin will <strong>view</strong> the seller profile under <strong>Manage Seller</strong>.</p><p>Under the <strong>Customer Information</strong> box, the admin will select <strong>Flags</strong> which will view the list of flags generated by the customers for that particular seller.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/seller-flag-reason-edited.webp" alt="seller reason
"></p><p>The admin can also take actions against the seller according to the flags. The admin can Deny/ Suspend the seller.</p><p>For this, the admin will navigate to **Marketplace Management &gt; Manage Sellers\xA0**and click on **deny **as shown in the image below:</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/manage-seller-3.webp" alt="manage seller"></p><h3 id="product-flag-management-magento-2-marketplace-extension-1" tabindex="-1"><a class="header-anchor" href="#product-flag-management-magento-2-marketplace-extension-1"><span>Product Flag Management: Magento 2 Marketplace Extension</span></a></h3><p>For managing the <strong>Product Flags</strong> configurations the admin will navigate to <strong>Stores &gt; Configuration &gt; Marketplace &gt;\xA0 Product Flags</strong>.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/product-flag-config-edited.webp" alt="product-flag-config"></p><p>As shown in the above image the admin will have to add the following field:</p><p>**Enable: **The admin will enable the product flag feature.</p><p>**Text: **This text will reflect the customer on the product page (front end).</p><p>**Guests Can Flag: **The admin will allow the guest users to report a flag against any product.</p><p>**Reason: **This field will show whether the reason is required or not. If this is set to <strong>Yes</strong> then below two fields will appear:</p><ul><li>Accept Other Reasons: If this field is set to yes then the customer will type their own reason otherwise they have to select from the available reasons.</li><li>Other Field’s Placeholder: This field will reflect only if the “Accept Other Reasons” field is set to yes. This will be the placeholder for the other reason field.</li></ul><p>**Note:\xA0**If this field is set to ‘Yes, Required’, make sure some reasons are created and enabled. The First 5 reasons will show on the flag creation page.</p><h3 id="product-flag-reasons" tabindex="-1"><a class="header-anchor" href="#product-flag-reasons"><span>Product Flag Reasons\xA0</span></a></h3><p>The admin can add multiple reasons for the product flags which will get selected by the customer while reporting the flag against any particular product.</p><p>For adding a new Flag reason the admin will navigate to **Marketplace Management &gt; Product Flag Reason **as shown in the image below:</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/mp-seller-flag-1200x796.webp" alt="mp-seller flag"></p><p>Admin can click on Product Flag Reason to check the reason list. The list includes the pre-added reasons.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/product-flag-reason-edited.webp" alt="Product flag reason"></p><p>Click on <strong>New Reason to add one more to the reason bucket. P</strong>rovide the details like <strong>Flag Reason</strong> and <strong>Status</strong> that a new reason will be added to the existing list of product flag reasons.</p><h3 id="customer-reports-flag-for-product" tabindex="-1"><a class="header-anchor" href="#customer-reports-flag-for-product"><span>Customer Reports Flag for Product\xA0</span></a></h3><p>After the admin configurations, the customers can raise issues by clicking on Report Product just below the Contact Seller Button.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/report-product-frontnend.webp" alt="report product "></p><p>After clicking on the Report Product, the customer will provide the report details. Details will be same for registered and guest customers.</p><p>**Note:\xA0**For the registered customers the Name and Email fields will be Auto-filled and Non-Editable ** **Whereas, for the guest customers the same will be Unfilled and Editable.</p><ul><li>Report Product Flag</li></ul><p>Under this, the customer can either select the existing reasons or add their own reason.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/report-product-sam-edited.webp" alt="report product"></p><p>After Submitting the form the details will be visible to the admin at the backend. For this, the admin will <strong>view</strong> the product in edit mode.</p><p>Under the Product Flags section the list of flags created will be visible which includes fields like **ID, Name, Email, Created Date, <strong>and ** Flag Reason</strong> as shown in the image below:</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/product-flag-reason-edited-1.webp" alt="product-flag-reason"></p><p>The admin can take actions against the product according to the flags. The admin can Deny/ Suspend the seller.</p><p>For this, the admin will navigate to **Marketplace Management &gt; Manage Product\xA0**and will click on **Deny **under Deny attribute as shown in the image below:</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/06/admin-remark-2.webp" alt="admin remark"></p><p>After that, the admin will have to provide the reason for denying the product. The admin can also check the checkbox to notify the respective seller via email about the denial of the product.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/reason-deny-product-edited.webp" alt="reason-deny-product"></p><p>After clicking on Deny, the product status will be changed to denied. The filter can be applied as shown in the image below:</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/mp-filter-seller-product.webp" alt="seller filter product"></p><p>Just after tapping the Done button, the product list will get filtered with the status as **Denied\xA0**as shown in the image below:</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/denied-product-looks-1200x508.webp" alt="denied"></p><h3 id="vendor-attribute" tabindex="-1"><a class="header-anchor" href="#vendor-attribute"><span>Vendor Attribute\xA0</span></a></h3><p>Now, the admin can add an attribute and allow it for sellers but only configurable or super attributes will be visible under vendor attributes at the admin end.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/mp-seller-flag-1-1200x796.webp" alt="MP dashboard"></p><p>Furthermore, the admin can create new attributes from <strong>Add New Attribute</strong> button and enable/disable added attributes in bulk mode from the <strong>Action</strong> tab.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/manage-attributes-edited.webp" alt="manae attributes"></p><p>If those configurable attributes are enabled for the vendor then we can see those attributes at <strong>vendor dashboard &gt; configurable attribute.</strong></p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/seller-products-edited.webp" alt="seller product"></p><h3 id="seller-product-settings-–" tabindex="-1"><a class="header-anchor" href="#seller-product-settings-–"><span>Seller Product Settings –</span></a></h3><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/seller-product-settings-956x1024.webp" alt="product setting
"></p><h4 id="attribute-set-id" tabindex="-1"><a class="header-anchor" href="#attribute-set-id"><span><strong>Attribute Set ID</strong></span></a></h4><p>Attribute Set ID is the default ID for your global catalog. Admin can select multiple attributes set from the Multi-Select list.</p><h4 id="product-approval-required" tabindex="-1"><a class="header-anchor" href="#product-approval-required"><span><strong>Product Approval Required</strong></span></a></h4><p>By this option, the admin can restrict automatic approval of the product e.g If the seller adds a product, every time the product will be moderated by the admin, the store owner can set <strong>YES or NO</strong>.</p><h4 id="product-update-approval-required" tabindex="-1"><a class="header-anchor" href="#product-update-approval-required"><span><strong>Product Update Approval Required</strong></span></a></h4><p>By this option, the admin can restrict automatic approval when a seller tries to update any parameter of the product.</p><p>e.g If a seller edits a product, every time the product will be moderated by admin, the store owner can set <strong>YES or NO</strong>.</p><h4 id="allow-category-tree-view-like-admin-product-category-tree" tabindex="-1"><a class="header-anchor" href="#allow-category-tree-view-like-admin-product-category-tree"><span><strong>Allow Category Tree View like admin product Category Tree</strong></span></a></h4><p>If this option is selected as “<strong>Yes</strong>“, then the seller on his ** add/edit product** page will find the category tree view for selecting the category for the products as is displayed.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/06/tree-category-1.webp" alt="tree view category"></p><h4 id="allowed-categories-for-the-seller-to-add-products" tabindex="-1"><a class="header-anchor" href="#allowed-categories-for-the-seller-to-add-products"><span><strong>Allowed Categories for the seller to add products</strong></span></a></h4><p>Using this field admin can restrict sellers to use only some selected categories to add products. Those categories which are not selected by the admin will not appear.</p><h3 id="product-type-for-seller" tabindex="-1"><a class="header-anchor" href="#product-type-for-seller"><span><strong>Product Type For Seller</strong></span></a></h3><p>Here admin will select different product types and these selected product types can be added by the seller from the front end.</p><h4 id="allow-seller-to-add-products-with-sku-type" tabindex="-1"><a class="header-anchor" href="#allow-seller-to-add-products-with-sku-type"><span><strong>Allow seller to add products with SKU type</strong></span></a></h4><p>Admin can allow the sellers to add the products with two types of SKUs – Static and Dynamic.</p><p>In the static type of SKU, Seller set SKU will be used.</p><p>In the dynamic type of SKU, automatically created SKU will be used.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2019/05/Dynamic-SKU.png" alt="Dynamic SKU"></p><h4 id="product-sku-prefix" tabindex="-1"><a class="header-anchor" href="#product-sku-prefix"><span><strong>Product SKU Prefix</strong></span></a></h4><p>The value put by the admin in this field will be added at initial to the SKU that will be set by the seller. Also, this field only applies to seller products.</p><p>For example – If SKU prefix = “xyz” &amp; product SKU is “T-Shirt” then, the product SKU becomes =&gt; xyzT-Shirt</p><h4 id="allow-seller-to-add-related-products" tabindex="-1"><a class="header-anchor" href="#allow-seller-to-add-related-products"><span><strong>Allow Seller to Add Related Products</strong></span></a></h4><p>Admin can allow sellers to add ‘Related Products’ while creating or editing products from the seller’s panel.</p><h4 id="allow-seller-to-add-up-sell-products" tabindex="-1"><a class="header-anchor" href="#allow-seller-to-add-up-sell-products"><span><strong>Allow Seller to Add Up-Sell Products</strong></span></a></h4><p>Admin can allow sellers to add ‘Up-Sell Products’ while creating or editing products from the seller’s panel.</p><h4 id="allow-seller-to-add-cross-sell-products" tabindex="-1"><a class="header-anchor" href="#allow-seller-to-add-cross-sell-products"><span><strong>Allow Seller to Add Cross-Sell Products</strong></span></a></h4><p>Admin can allow sellers to add ‘Cross-Sell Products’ while creating or editing products from the seller’s panel.</p><h4 id="allow-seller-to-add-limit-on-product-purchase-for-customer" tabindex="-1"><a class="header-anchor" href="#allow-seller-to-add-limit-on-product-purchase-for-customer"><span><strong>Allow Seller to Add Limit on Product Purchase for Customer</strong></span></a></h4><p>Admin can allow the seller to set product purchase quantity limits for buyers.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2019/05/Configuration-Settings.png" alt="Configuration Settings"></p><h4 id="if-admin-allowed-limit-on-the-product-qty-on-product-purchase-for-customer" tabindex="-1"><a class="header-anchor" href="#if-admin-allowed-limit-on-the-product-qty-on-product-purchase-for-customer"><span><strong>If Admin Allowed limit on the Product Qty on Product Purchase for Customer</strong></span></a></h4><p>Here admin can enter the default value that will use when the seller does not set any product purchase limit.</p><p>For example, if the admin set a default 5 product purchase quantity and the seller do not set any limit then the customer can only buy 5 product quantity.</p><p>If the seller sets some product quantity limit then that limit will be used.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/maximum-quantity-5-edited.webp" alt="maximum-quantity-5"></p><h3 id="seller-order-s-settings-magento-2-marketplace-extension" tabindex="-1"><a class="header-anchor" href="#seller-order-s-settings-magento-2-marketplace-extension"><span>Seller Order’s Settings : Magento 2 Marketplace Extension</span></a></h3><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/seller-order-settings-1200x796.webp" alt="seller order"></p><h4 id="order-approval-required" tabindex="-1"><a class="header-anchor" href="#order-approval-required"><span><strong>Order Approval Required</strong></span></a></h4><p>When set as “Yes”, the admin is to approve each order manually, and only after that the seller will get notified about the order.</p><p>If this is set to “No”, the order notification will automatically be sent to the seller.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/order-approval-edited.webp" alt="order-approval"></p><p>When the admin approves an order, the seller will receive and notification email and then the seller will be able to manage and view the order from his seller’s panel.</p><h3 id="inventory-settings-seller-profile-page-settings" tabindex="-1"><a class="header-anchor" href="#inventory-settings-seller-profile-page-settings"><span>Inventory Settings &amp; Seller Profile Page Settings</span></a></h3><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/inventory-settimgs.webp" alt="inventory setting
"></p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/seller-profile-page-settimgs.webp" alt="seller profile page setting
"></p><h4 id="enable-low-notification" tabindex="-1"><a class="header-anchor" href="#enable-low-notification"><span><strong>Enable Low Notification</strong></span></a></h4><p>If “Enable Low Notification” is selected as “Yes”, then seller get notified through their e-mails when their inventory decreases with subsequent orders.</p><h4 id="low-stock-quantity" tabindex="-1"><a class="header-anchor" href="#low-stock-quantity"><span><strong>Low Stock Quantity</strong></span></a></h4><p>Here admin will enter low stock quantity, which will allow sending a low stock notification mail to sellers when product quantity will be equal to or less than this quantity.</p><h4 id="banner-image" tabindex="-1"><a class="header-anchor" href="#banner-image"><span>Banner Image\xA0</span></a></h4><p>The admin can change the default seller’s banner image from here.</p><h4 id="display-seller-profile" tabindex="-1"><a class="header-anchor" href="#display-seller-profile"><span><strong>Display Seller Profile</strong></span></a></h4><p>If the admin set this to “yes”, then the seller information will be visible under the Marketplace Dashboard menu, on the product and on the landing page.</p><p>If the admin set this option as disabled, then the seller information will be hidden from the Marketplace Dashboard, product, and the Marketplace landing page.</p><p>Also, the seller will not be able to see the customer details, that will be hidden on the Order View page, Shipping slip, Invoice, Credit Memo page.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/mp-shop-956x1024.webp" alt="MP shop "></p><h4 id="seller-information-display-card-type" tabindex="-1"><a class="header-anchor" href="#seller-information-display-card-type"><span><strong>Seller Information Display Card Type</strong></span></a></h4><p>The seller information can be displayed on the product page for which the admin can select the desired design or card type as Type 1 and Type 2.</p><p>This is done to display the information about the seller which the customer can view and refer to.</p><h5 id="if-admin-selects-card-type-as-type-1" tabindex="-1"><a class="header-anchor" href="#if-admin-selects-card-type-as-type-1"><span><em><strong>If Admin selects Card Type as Type 1-</strong></em></span></a></h5><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/type_1_Seller.png" alt="type_1_Seller"></p><h4 id="if-admin-selects-card-type-as-type-2" tabindex="-1"><a class="header-anchor" href="#if-admin-selects-card-type-as-type-2"><span><strong>If Admin selects Card Type as Type 2-</strong></span></a></h4><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/type2_card.png" alt="type2_card"></p><h4 id="enable-color-picker" tabindex="-1"><a class="header-anchor" href="#enable-color-picker"><span><strong>Enable Color Picker</strong></span></a></h4><p>If this option is set to “Yes”, then the seller can change their profile page background color as per their need.</p><h4 id="seller-policies-enable-at-the-frontend" tabindex="-1"><a class="header-anchor" href="#seller-policies-enable-at-the-frontend"><span><strong>Seller Policies Enable at the frontend</strong></span></a></h4><p>There is an option – ” Seller policies Enable at frontend ” if the admin sets it as “Yes”, then the seller shipping, returns, shipping policies, and privacy policies will be visible at the frontend.</p><p>If the admin has set it as “No”, then the shipping and other policies will not be visible at the front end.</p><h3 id="rewrite-seller-s-shop-url" tabindex="-1"><a class="header-anchor" href="#rewrite-seller-s-shop-url"><span><strong>Rewrite Seller’s Shop URL</strong></span></a></h3><p>When this option is set “Yes”, then the seller can change the URL to any name they want, and then that new name will appear.</p><p>The seller can change the Url of the Profile page, Review page, Collection page &amp; Location page.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/urlexample.png" alt="example"></p><h4 id="allow-to-automatic-create-seller-public-url-on-seller-registration" tabindex="-1"><a class="header-anchor" href="#allow-to-automatic-create-seller-public-url-on-seller-registration"><span><strong>Allow to automatic create seller public URL on Seller registration</strong></span></a></h4><p>If the admin select “<strong>Yes</strong>” for this field then when a new customer creates a new account it automatically creates the seller public URL at the time of registration.</p><p>If the admin set this option as “<strong>No</strong>“, then the seller will have to manually add his rewrite URLs.</p><h4 id="allow-showing-featured-sellers" tabindex="-1"><a class="header-anchor" href="#allow-showing-featured-sellers"><span><strong>Allow showing featured sellers</strong></span></a></h4><p>The admin can enable this option to show the featured sellers on various locations of the front-end. Featured sellers can be added in:</p><ol><li>Pages</li><li>Blocks</li></ol><p>In the case of Pages:</p><p>The admin needs to navigate through **Content &gt; Pages\xA0**as per below image:</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/1-content-pages.webp" alt="content-pages"></p><p>After that admin can create a new page or edit the existing one by selecting edit option under action.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/06/about-us-edit-1.webp" alt="about us edit page"></p><h3 id="insert-widget" tabindex="-1"><a class="header-anchor" href="#insert-widget"><span>Insert Widget</span></a></h3><p>Now, admin has to select <strong><strong>Edit with page builder &gt;Edit HTML Code&gt; Insert Widget</strong></strong> under the ** Content\xA0**as per the below image:</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/06/about-us-widget-1.webp" alt="about us widget"></p><p>After clicking on **Insert Widget\xA0**the admin can select <strong>Widget Type</strong> as <strong>Vendor Featured</strong> to display the seller profile at the front end.</p><p>For the reference see the below image:</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/insert-widgets.png" alt="insert-widgets"></p><p>***Note:- Herein, an extra Transaction effect option will be visible only in the case of the Magento Enterprise edition. ***</p><p><em><strong>Otherwise, in the case of the community edition, the field will be the same as above.</strong></em></p><h4 id="widget-type" tabindex="-1"><a class="header-anchor" href="#widget-type"><span><strong>Widget Type:</strong></span></a></h4><p>Select the Widget Type as <strong>Vendor Featured</strong> to show the seller profile at the front end.</p><h4 id="widget-options" tabindex="-1"><a class="header-anchor" href="#widget-options"><span><strong>widget Options:</strong></span></a></h4><p><strong>Transaction Time</strong>– Here the admin has to enter the transaction time in milliseconds which decides the transaction time between two featured sellers.</p><p><strong>Width</strong>– This will decide the width of the seller featured profile which will display on the front end.</p><p><strong>The ratio of Height-</strong> Width- The Admin can decide the ratio of height and width of the featured seller profile display.</p><p><strong>Seller Ids</strong>– Admin has to enter the Ids of the seller which they want to show at the front end and each seller Ids are separate by a comma.</p><h4 id="front-end-view" tabindex="-1"><a class="header-anchor" href="#front-end-view"><span><strong>Front-End view</strong></span></a></h4><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/About-us_featured_seller-1.png" alt="multi vendow marketplace"></p><h3 id="in-the-case-of-blocks" tabindex="-1"><a class="header-anchor" href="#in-the-case-of-blocks"><span><strong>In the case of Blocks</strong></span></a></h3><p>The admin has to navigate through **Content &gt; Blocks **as per below image:</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/1-content-pages-1.webp" alt="content-block"></p><p>After that admin can create a new Block or edit the existing one by selecting edit option under action.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/content-block.webp" alt="content-block"></p><p>Now, Admin has to select **Edit with page builder &gt;Edit HTML Code&gt; Insert Widget\xA0**under the ** Content\xA0**as per below image:</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/content-information-edited.webp" alt="content-information"></p><p>After clicking on **Insert Widget\xA0**the admin can select <strong>Widget Type</strong> as <strong>Vendor Featured</strong> to display the seller profile at the front end.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/insert-widgets-1.png" alt="insert-widgets"></p><p>Here, the admin has to enter</p><ul><li>Transaction Time between two featured sellers,</li><li>Width of the featured seller profile,</li><li>Seller Ids of the sellers which they want to make visible on the front-end and</li><li>The ratio of Height: The admin will select the width.</li></ul><h2 id="storefront-view-–-magento-2-marketplace-extension" tabindex="-1"><a class="header-anchor" href="#storefront-view-–-magento-2-marketplace-extension"><span>Storefront View – Magento 2 Marketplace Extension</span></a></h2><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/Contact-Us_featured_seller.jpg" alt="multi vendow marketplace"></p><h3 id="marketplace-seller-review-settings" tabindex="-1"><a class="header-anchor" href="#marketplace-seller-review-settings"><span>Marketplace Seller Review Settings</span></a></h3><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/seller-review-setting.png" alt="Marketplace Seller Review Settings"></p><p>When Marketplace Seller Review is set to “YES”, then the customer can make a review only after the purchase and if “NO” is selected then the customer can make a review before the product purchase.</p><h4 id="landing-page-settings" tabindex="-1"><a class="header-anchor" href="#landing-page-settings"><span><strong>Landing Page Settings</strong></span></a></h4><p>From here admin can enable or disable the Seller registration from Customer Registration Page. Admin can also choose from the 3 layouts and customize them as per their need.</p><h4 id="display-seller-registration-block-on-customer-registration-page" tabindex="-1"><a class="header-anchor" href="#display-seller-registration-block-on-customer-registration-page"><span><strong>Display Seller Registration Block on Customer Registration Page</strong></span></a></h4><p>From here admin can enable or disable the seller registration from the customer registration page.</p><p>When selected ‘No’</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/landing-settings-no.webp" alt="Landing settings - NO"></p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/become-seller-no.webp" alt="become-seller-no"></p><p>When the option is set as “No”, and if Layout 2 or 3 is selected then it will work as a Seller Central. For detailed information about this, you check the</p><p>Marketplace Seller Central Blog at <a href="https://webkul.com/blog/magento2-marketplace-seller-central/" target="_blank" rel="noopener noreferrer">https://webkul.com/blog/magento2-marketplace-seller-central/</a>.</p><p>When selected ‘Yes’</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/landing-settings-yes.webp" alt="landing-settings-yes"></p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/become-seller-yes.webp" alt="become seller"></p><h4 id="layout-configuration" tabindex="-1"><a class="header-anchor" href="#layout-configuration"><span><strong>Layout Configuration</strong></span></a></h4><p><strong>Case 1: When Layout1 is selected</strong></p><p><strong>Admin Panel</strong></p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/mp-landing-page-settings-1-956x1024.webp" alt="mp-landing-page-settings-1"></p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/mp-landing-page-settings-2.webp" alt="mp-landing-page-settings-2
"></p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/mp-landing-page-settings-3.webp" alt="mp-landing-page-settings-3
"></p><h4 id="marketplace-landing-page-layout" tabindex="-1"><a class="header-anchor" href="#marketplace-landing-page-layout"><span><strong>Marketplace Landing Page Layout</strong></span></a></h4><p>Here admin can choose from various layouts that will be shown on the front-end.</p><h4 id="marketplace-landing-page-head-title" tabindex="-1"><a class="header-anchor" href="#marketplace-landing-page-head-title"><span><strong>Marketplace Landing Page Head Title</strong></span></a></h4><p>Here admin will enter the Head title of the Marketplace landing page and that name will appear on the front-end.</p><h4 id="display-banner-banner-image-banner-content" tabindex="-1"><a class="header-anchor" href="#display-banner-banner-image-banner-content"><span><strong>Display Banner, Banner Image &amp; Banner Content</strong></span></a></h4><p>Here admin will enable the option “Display Banner” so that the banner will be displayed on the front-end.</p><p>In the “Banner Image” section, the admin will choose and upload the banner image.</p><p>For the “Banner Content”, the admin will write the content which will be displayed over the banner image in the Marketplace.</p><h4 id="marketplace-landing-page-label-1" tabindex="-1"><a class="header-anchor" href="#marketplace-landing-page-label-1"><span><strong>MarketPlace Landing Page Label 1</strong></span></a></h4><p>Here admin will enter some catchy lines and it will be displayed above all feature’s icons.</p><h4 id="marketplace-landing-page-label-2" tabindex="-1"><a class="header-anchor" href="#marketplace-landing-page-label-2"><span><strong>Marketplace Landing Page Label 2</strong></span></a></h4><p>Here admin will enter some content that will be displayed above the top 4 seller blocks.</p><h4 id="marketplace-landing-page-label-3" tabindex="-1"><a class="header-anchor" href="#marketplace-landing-page-label-3"><span><strong>Marketplace Landing Page Label 3</strong></span></a></h4><p>Here, Admin will enter the content for displaying the above “View All Seller” button.</p><h4 id="marketplace-landing-page-label-4" tabindex="-1"><a class="header-anchor" href="#marketplace-landing-page-label-4"><span><strong>Marketplace Landing Page Label 4</strong></span></a></h4><p>Here admin will enter the content for displaying above marketplace content.</p><h4 id="marketplace-landing-page-button-label" tabindex="-1"><a class="header-anchor" href="#marketplace-landing-page-button-label"><span><strong>Marketplace Landing Page Button Label</strong></span></a></h4><p>Here admin will enter the label for the landing page button label and it will get displayed on banners.</p><h4 id="display-icons" tabindex="-1"><a class="header-anchor" href="#display-icons"><span><strong>Display Icons-</strong></span></a></h4><p>Admin can set this as “Yes or No” and then anyone can see Feature icon and Feature label.</p><p>Likewise, the admin will select for all the Feature icons 1,2,3,4 and Feature Label and it will be displayed as per the admin setting.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/exampleicones.png" alt="example"></p><h4 id="about-marketplace" tabindex="-1"><a class="header-anchor" href="#about-marketplace"><span><strong>About Marketplace</strong></span></a></h4><p>Here admin will enter the content inside the box provided.</p><h4 id="marketplace-seller-list-page-bottom-label" tabindex="-1"><a class="header-anchor" href="#marketplace-seller-list-page-bottom-label"><span><strong>Marketplace Seller List Page Bottom Label</strong></span></a></h4><p>Here admin will enter the label which will be displayed at the bottom of the MarketPlace Seller List Page.</p><h4 id="marketplace-seller-list-page-top-label" tabindex="-1"><a class="header-anchor" href="#marketplace-seller-list-page-top-label"><span><strong>Marketplace Seller List Page Top Label</strong></span></a></h4><p>Here admin will enter the label which will be displayed at the top of the MarketPlace Seller List Page.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/mp-landing-page-ss-1-2-853x1024.webp" alt="mp-landing-page-ss-11"></p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/mp-landing-page-ss-1-2-1-853x1024.webp" alt="mp-landing-page-ss-1-2"></p><p><strong>Case 2: When Layout 2 is selected</strong></p><p><strong>Admin Panel</strong></p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/mp-landing-page-layout-2.webp" alt="mp-landing-page-layout-2"></p><h4 id="marketplace-landing-page-layout-1" tabindex="-1"><a class="header-anchor" href="#marketplace-landing-page-layout-1"><span><strong>Marketplace Landing Page Layout</strong></span></a></h4><p>Here admin can choose from various layouts that will be shown on the front-end.</p><h4 id="marketplace-landing-page-head-title-1" tabindex="-1"><a class="header-anchor" href="#marketplace-landing-page-head-title-1"><span><strong>Marketplace Landing Page Head Title</strong></span></a></h4><p>Here admin will enter the Head title of the Marketplace landing page and that name will appear on the front end.</p><h4 id="display-banner-banner-image-banner-content-1" tabindex="-1"><a class="header-anchor" href="#display-banner-banner-image-banner-content-1"><span><strong>Display Banner, Banner Image &amp; Banner Content</strong></span></a></h4><p>Here admin will enable the option “Display Banner” so that the banner will be displayed on the front-end.</p><p>In the “Banner Image” section, the admin will choose and upload the banner image.</p><p>For the “Banner Content”, the admin will write the content which will be displayed over the banner image in the Marketplace.</p><h4 id="marketplace-landing-page-button-label-1" tabindex="-1"><a class="header-anchor" href="#marketplace-landing-page-button-label-1"><span><strong>Marketplace Landing Page Button Label</strong></span></a></h4><p>Here admin will enter the label for the landing page button label and it will get displayed on banners.</p><h4 id="terms-and-conditions-url" tabindex="-1"><a class="header-anchor" href="#terms-and-conditions-url"><span><strong>Terms and Conditions URL</strong></span></a></h4><p>Here admin has to enter the Terms &amp; Conditions Page link address.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/mp-landing-page-ss-2-853x1024.webp" alt="mp-landing-page"></p><p><strong>Case 3: When Layout3 is selected</strong></p><p><strong>Admin Panel</strong></p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/mp-landing-page-layout-3.webp" alt="Layout 3 landing page"></p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/2-layout-956x1024.webp" alt="layout-3-landing page"></p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/3-layout.webp" alt="landing-page layout 3"></p><h4 id="marketplace-landing-page-layout-2" tabindex="-1"><a class="header-anchor" href="#marketplace-landing-page-layout-2"><span><strong>Marketplace Landing Page Layout</strong></span></a></h4><p>Here admin can choose from various layouts that will be shown on the front end.</p><h4 id="marketplace-landing-page-head-title-2" tabindex="-1"><a class="header-anchor" href="#marketplace-landing-page-head-title-2"><span><strong>Marketplace Landing Page Head Title</strong></span></a></h4><p>Here admin will enter the Head title of the Marketplace landing page and that name will appear on the front-end.</p><h4 id="display-banner-banner-image-banner-content-2" tabindex="-1"><a class="header-anchor" href="#display-banner-banner-image-banner-content-2"><span><strong>Display Banner, Banner Image &amp; Banner Content</strong></span></a></h4><p>Here admin will enable the option “Display Banner” so that the banner will be displayed on the front-end.</p><p>In “Banner Image” section, the admin will choose and upload the banner image.</p><p>For the “Banner Content”, the admin will write the content which will be displayed over the banner image in the Marketplace.</p><h4 id="marketplace-landing-page-button-label-2" tabindex="-1"><a class="header-anchor" href="#marketplace-landing-page-button-label-2"><span><strong>Marketplace Landing Page Button Label</strong></span></a></h4><p>Here admin will enter the label for the landing page button label and it will get displayed on banners.</p><h4 id="marketplace-landing-page-label-1-1" tabindex="-1"><a class="header-anchor" href="#marketplace-landing-page-label-1-1"><span><strong>Marketplace Landing Page Label 1</strong></span></a></h4><p>Here admin will enter some catchy lines and it will be displayed above all feature’s icons.</p><h4 id="marketplace-landing-page-label-2-1" tabindex="-1"><a class="header-anchor" href="#marketplace-landing-page-label-2-1"><span><strong>Marketplace Landing Page Label 2</strong></span></a></h4><p>Here admin will enter some content that will be displayed above the top 4 seller blocks.</p><p><strong>Marketplace Landing Page Label 3</strong></p><p>Here, Admin will enter the content for displaying above the “View All Seller” button.</p><h4 id="display-icons-1" tabindex="-1"><a class="header-anchor" href="#display-icons-1"><span><strong>Display Icons-</strong></span></a></h4><p>Admin can set this as “Yes or No” and then anyone can see the Feature icon and Feature label.</p><p>Likewise, the admin will select all the Feature icons 1,2,3,4,5, and Feature Label and it will be displayed as per the admin setting.</p><p>Admin will explain the overall workflow of the Marketplace through the five icons.</p><p>Any Seller can register themselves in the Marketplace, they can customize their profile and add details, then add products for their shops.</p><p>After adding the product, selling will be done and they will generate profit from sales.</p><h4 id="terms-and-conditions-url-1" tabindex="-1"><a class="header-anchor" href="#terms-and-conditions-url-1"><span><strong>Terms and Conditions URL</strong></span></a></h4><p>Here admin has to enter the Terms &amp; Conditions Page link address.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/mp-landing-page-ss-3-1-edited.webp" alt="mp-landing-page"></p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/mp-landing-page-ss-3-2-1200x796.webp" alt="mp-landing-page-ss-3-2"></p><h4 id="seller-layered-navigation-magento-2-multi-vendor-extension" tabindex="-1"><a class="header-anchor" href="#seller-layered-navigation-magento-2-multi-vendor-extension"><span><strong>Seller Layered Navigation: Magento 2 Multi Vendor Extension</strong></span></a></h4><p>Using this field the admin can enable a section of layered navigation on the category collection page.</p><p><strong>Display Seller Filter in Layered Navigation</strong>– The admin can set this section to ‘Yes’, in order to enable the filter on the product page.</p><h4 id="display-name-for-admin-in-layered-navigation–" tabindex="-1"><a class="header-anchor" href="#display-name-for-admin-in-layered-navigation–"><span><strong>Display Name for Admin in Layered Navigation</strong>–</span></a></h4><p>This section contains the information in which way the admin wishes to display his/her name in the layered navigation section.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/Configuration-Settings-Stores-Magento-Admin.png" alt="Configuration Settings Stores Magento Admin"></p><p>Henceforth, in the frontend the navigation which appears as below-</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/06/seller-admin-filter-1.webp" alt="seller-filter"></p><p>The customer can apply the filter here to sort out the products of desired sellers.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/06/filetr-apply-1.webp" alt="filter-seller-apply"></p><h2 id="seller-s-sitemap-settings" tabindex="-1"><a class="header-anchor" href="#seller-s-sitemap-settings"><span>Seller’s Sitemap settings</span></a></h2><p>The admin can manage the seller’s sitemap setting from the admin dashboard. To manage the sitemap, the admin can navigate to <strong>Store&gt; configuration&gt; marketplace&gt; seller’s sitemap setting</strong>.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/seller-sitemap-settings.webp" alt="Seller sitemap settings"></p><ul><li>Allow Seller’s Url in Sitemap– The admin can enable or disable the seller’s url in the sitemap</li><li>Allow Seller’s Profile Url in Sitemap– The admin can enable or disable the seller’s profile in the sitemap</li><li>Seller’s Profile URL Frequency in Sitemap– The admin can set the frequency to update the seller’s profile in the sitemap accordingly.</li><li>Seller’s Profile <strong>URL</strong> Priority in sitemap–\xA0 The admin can set the priority of the seller’s profile from low to high (0.0 to 1.0)</li><li>Allow Seller’s Collection <strong>URL</strong> In Sitemap– The admin can enable or disable the seller’s collection in the sitemap</li><li>Seller’s Collection <strong>URL</strong> frequency in Sitemap– The admin can set the frequency to update the collection URL in the sitemap</li><li>Seller’s Collection <strong>URL</strong> Priority in Sitemap– The admin can set the priority of the collection URL in the sitemap.</li></ul><p>Now, the admin can manage and add sitemap from the <strong>Marketing&gt; Site Map</strong> from the admin dashboard.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/marketing-sitemap-edited.webp" alt="marketing site map
"></p><p>Here, the admin can add a new Sitemap or edit the existing one.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/list-of-site-map.webp" alt="list-of-site-map"></p><p>The admin can even manage the existing one sitemap by clicking on the file name. When clicked on the URL, the admin will redirect to the sitemap.</p><p>To add a new sitemap, the admin can click on **Add Sitemap,\xA0**here the admin will have to enter the filename, path.</p><p>Select the store view for which the admin wants to generate the sitemap and then click on save.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/add-new-site-map.webp" alt="add-new-site-map"></p><p>This is how the sitemap can be generated from the admin dashboard for the seller’s profile and seller’s collection page.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/webkul-magento2-multi-vendor-mp-site-map-1.png" alt="webkul-magento2-multi-vendor-mp-site-map-1"></p><h3 id="marketplace-profile-page-fields-hints" tabindex="-1"><a class="header-anchor" href="#marketplace-profile-page-fields-hints"><span>Marketplace Profile Page Fields Hints</span></a></h3><p>Using this field, admin can Enable or Disable the profile hints.</p><p>Including shop URL, profile id, Profile Payment Information, Profile Meta Description, Profile Meta Keywords, Shipping &amp; Return Policies and many more.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2019/05/webkul_magento2_marketplace_profile_hints.png" alt="webkul_magento2_marketplace_profile_hints"></p><h3 id="marketplace-product-page-fields-hints" tabindex="-1"><a class="header-anchor" href="#marketplace-product-page-fields-hints"><span>Marketplace Product Page Fields Hints</span></a></h3><p>Using this field, the admin can Enable or Disable the product page fields hints which will assist the seller while adding a product.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/mp-profile-page-hint-1-956x1024.webp" alt="mp-profile-page-hint-1"></p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/mp-profile-page-hint-2-956x1024.webp" alt="mp-profile-page-hint-2"></p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/mp-profile-page-hint-3-956x1024.webp" alt="mp-profile-page-hint-3"></p><h2 id="marketplace-transactional-emails-–-magento-2-marketplace-extension" tabindex="-1"><a class="header-anchor" href="#marketplace-transactional-emails-–-magento-2-marketplace-extension"><span>Marketplace Transactional Emails – Magento 2 Marketplace Extension</span></a></h2><p>Now, admin can select the custom templates from <strong>Marketing &gt; Communications (Email Template)</strong>.</p><p>Created custom templates will be added to the drop-down and admin can use the desired template.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/add-new-template-956x1024.webp" alt="add-new-template"></p><p>Admin can select the created template like this-</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/transaction-email-1-956x1024.webp" alt="email-1"></p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/transaction-email-2.webp" alt="transaction-email-2"></p><h3 id="marketplace-landing-page" tabindex="-1"><a class="header-anchor" href="#marketplace-landing-page"><span>Marketplace Landing Page</span></a></h3><p>The Marketplace Extension is based upon a responsive theme which makes the marketplace landing page more beautiful than before, incorporating an alluring banner with its content.</p><p>The page is divided into 4 different labels, between the Banner Image and Footer links, showing icons like Registering Yourself, Adding products, Start Selling, and Generating Revenues.</p><p>The second label will display the top 4 sellers of the marketplace, with their top three selling products, Seller logo, Shop Title, and a button to redirect to view the full collection of the seller.</p><p>The label also contains the option to ‘view the list of all the sellers of the marketplace at one place.</p><p>You can see there are four icons that display the overall working of the Marketplace in a list. Any Seller can register themselves in the Marketplace, then add products for their shops.</p><p>After adding the products into their shops, selling will be done and then revenue will be generated for the sale.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/mp-landing-page-ss-1-1-853x1024.webp" alt="mp-landing-page-ss-1"></p><p>After clicking on View All, you will be redirected to a new page, where the customer can search seller by a shop and all the seller’s information will be there along with the seller’s logo.</p><p>There will be a “View All” button which will display all the products of the seller.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/mp-webkul-store-1200x986.webp" alt="mp-webkul-store"></p><h2 id="new-vendor-sign-up-–-magento-2-marketplace-extension" tabindex="-1"><a class="header-anchor" href="#new-vendor-sign-up-–-magento-2-marketplace-extension"><span>New Vendor Sign-Up – Magento 2 Marketplace Extension</span></a></h2><p>Seller signup is very easy, the user can signup for the seller using the marketplace landing page button.</p><p>Or from the store My Account link, and during signup, they need to choose “Want To Become Partner”.</p><p>If they want to signup as a seller then they need to choose YES else NO. If they choose YES then they need to put their shop URL which will be unique as per the screenshot.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/customer-login-901x1024.webp" alt="mp vendor login
"></p><p>The shop URL input field is Ajax driven by which the seller can see whether that particular URL exists or not as below screens. As per the screen, that URL exists.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/shop-name-available.webp" alt="vendor-url-shop"></p><p>As per the below screen, that URL does not exist.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/shop-name-unavailable-1.webp" alt="shop-name-unavailable"></p><h2 id="marketplace-seller-panel-management" tabindex="-1"><a class="header-anchor" href="#marketplace-seller-panel-management"><span>Marketplace Seller Panel Management</span></a></h2><p>After approval as a seller, the marketplace dashboard will be available to the seller. So, the seller can edit their profile, add new products, and delete their products.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/mp-seller-dashboard-edited.webp" alt="Marketplace seller dashboard"></p><p>The seller can also view the notification count for product approval, new orders placed, and new transactions.</p><p>As well as view their transaction list, customer list, review, and order history and draft products.</p><p>Here, You can check your draft product and from select option you can edit or delete them.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/draft-product-edited.webp" alt="draft product"></p><p>The sellers can even click the notification bell icon to quickly view the new notifications for products, transactions, and orders. Please refer to the screenshot.</p><p>You can see there are many tabs for the base Magento 2 Marketplace Extension to manage the seller profile and to add a product in the store. Let us explain all of them.</p><h3 id="seller-profile" tabindex="-1"><a class="header-anchor" href="#seller-profile"><span>Seller Profile</span></a></h3><h4 id="edit-seller-profile-information" tabindex="-1"><a class="header-anchor" href="#edit-seller-profile-information"><span>Edit Seller Profile Information</span></a></h4><p>Using this menu seller will have shop information like shop name, the location of their shop, banner image, shop logo, company locality, shop meta description, and many more parameters.</p><p>In the Seller profile panel, the seller can add their various social media links, contact number, Background color.</p><p>(if enabled by the admin), Shop title, Company Banner, Company Logo, Tax/Vat number, and Payment details, Policy details, etc.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/seller-profile-ss-1-901x1024.webp" alt="MP edit seller profile"></p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/seller-profile-ss-2-901x1024.webp" alt="seller-profile-ss-2"></p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/seller-profile-ss-3-901x1024.webp" alt="seller-profile-ss-3"></p><h4 id="edit-seller-shop-url" tabindex="-1"><a class="header-anchor" href="#edit-seller-shop-url"><span>Edit Seller Shop URL-</span></a></h4><p>One can now edit the different Shop page’s URLs as required for Profile Page, Collection Page, Review page &amp; Location Page,</p><p>Then can set it accordingly as shown in the screenshot, which will be displayed in the URL of the particular page requested.</p><p>The seller can manage the custom URL for the shop.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/edit-seller-shop-url-901x1024.webp" alt="edit-seller-shop-url"></p><h4 id="edit-seller-payment-information" tabindex="-1"><a class="header-anchor" href="#edit-seller-payment-information"><span>Edit Seller Payment Information-</span></a></h4><p>Under the <strong>Payment Details</strong>, the seller can add their bank account or PayPal id or any kind of payment information.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/paymentseller.png" alt="image"></p><h2 id="seller-profile-view" tabindex="-1"><a class="header-anchor" href="#seller-profile-view"><span>Seller Profile View</span></a></h2><p>The admin can set the seller profile view layout by navigating through <strong>Marketplace Management &gt;&gt; Configuration &gt;&gt; Seller Profile Page Settings</strong></p><p><strong>Case 1</strong>: If the admin selects the Layout 1.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/seller-profile-page-setting-1-901x1024.webp" alt="seller profile page
"></p><h2 id="frontend-view-of-seller-s-profile-–-layout-1" tabindex="-1"><a class="header-anchor" href="#frontend-view-of-seller-s-profile-–-layout-1"><span>Frontend View of Seller’s Profile – Layout 1</span></a></h2><p>After entering all the information, sellers will get an amazing page for their shop as below.</p><h4 id="seller-s-profile-page" tabindex="-1"><a class="header-anchor" href="#seller-s-profile-page"><span>Seller’s Profile Page</span></a></h4><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/seller_profil_page_.png" alt="seller_profil_page_Multi Vendor"></p><p>The customer ratings are visible on the seller profile page as shown below in the snapshot.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/seller_review.png" alt="seller_review"></p><h4 id="seller-s-collection-page" tabindex="-1"><a class="header-anchor" href="#seller-s-collection-page"><span>Seller’s Collection Page</span></a></h4><p>When the user will click on “Products” or “View All Products”, the user will be able to see all the Seller’s Product which can be browsed by categories.</p><p>From here buyer can add a product to his cart and proceed to further process.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/john_s_store.png" alt="john_s_store"></p><h4 id="seller-s-product-page" tabindex="-1"><a class="header-anchor" href="#seller-s-product-page"><span>Seller’s Product Page</span></a></h4><p>In the product page, the customer can view the review for that particular product along with the shop link for that seller as shown in the below image.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/report-product-frontnend-1.webp" alt="report product"></p><h4 id="contact-seller" tabindex="-1"><a class="header-anchor" href="#contact-seller"><span>Contact Seller</span></a></h4><p>When the buyer clicks on the “Contact Seller” button on the Seller’s product page then the popup for the contact seller will open.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/report-product-sam-1.webp" alt="report product sam"></p><h4 id="email-template-for-product-page-contact-seller" tabindex="-1"><a class="header-anchor" href="#email-template-for-product-page-contact-seller"><span>\xA0Email Template For Product Page Contact Seller</span></a></h4><p>The admin can set the email template for the product page to contact the seller by clicking on <strong>Stores&gt;Configuration&gt;Marketplace Transactional Emails&gt;Ask Question to Seller Regarding Product Template.</strong></p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/transaction-email-1-1-956x1024.webp" alt="transaction email"></p><h4 id="seller-s-feedback-page" tabindex="-1"><a class="header-anchor" href="#seller-s-feedback-page"><span>Seller’s Feedback Page</span></a></h4><p>Buyers can rate the seller according to his/her opinion under their profile with star rate votes and feedback messages as shown below.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/write-your-review.png" alt="write-your-review"></p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2019/05/review.png" alt="review"></p><h4 id="seller-s-location-page" tabindex="-1"><a class="header-anchor" href="#seller-s-location-page"><span>Seller’s Location Page</span></a></h4><p>By clicking on the seller location below the Seller’s shop name the buyer will be redirected to the seller’s location(for showing location, please add the company locality of the seller) page.</p><p>From the seller’s location, page buyers can view the seller’s location on the map.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/seller_map.png" alt="seller_map"></p><p><strong>Case 2</strong>: If the admin selects the Layout 2.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/seller-profile-page-seeting-2.webp" alt="seller settings"></p><h2 id="frontend-view-of-seller-s-profile-–-layout-2" tabindex="-1"><a class="header-anchor" href="#frontend-view-of-seller-s-profile-–-layout-2"><span>Frontend View of Seller’s Profile – Layout 2</span></a></h2><p>If Layout 2 is selected in Seller profile page settings then the seller will get amazing page for their shop as given below.</p><h3 id="sellers-profile-page" tabindex="-1"><a class="header-anchor" href="#sellers-profile-page"><span>Sellers Profile Page</span></a></h3><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/M2MP11.png" alt="M2MP11"></p><h3 id="" tabindex="-1"><a class="header-anchor" href="#"><span><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/M2Mp12.png" alt="M2Mp12"></span></a></h3><p>The customer ratings are visible on the seller profile page as shown below in the snapshot.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/m2mp13.png" alt="m2mp13"></p><h4 id="seller-s-collection-page-1" tabindex="-1"><a class="header-anchor" href="#seller-s-collection-page-1"><span>Seller’s Collection Page</span></a></h4><p>When user will click on “Products” or “View All Products”, the user will be able to see all the Seller’s Product which can be browsed by categories.</p><p>From here buyer can add a product to his cart and proceed to further process.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/m2mp14.png" alt="m2mp14"></p><h4 id="contact-seller-1" tabindex="-1"><a class="header-anchor" href="#contact-seller-1"><span>Contact Seller</span></a></h4><p>When the buyer clicks on the “Contact Seller” tab on the seller’s profile page, then the popup for the contact seller will open.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/Screenshot-24.png" alt="Screenshot-24"></p><h4 id="email-template-for-contact-seller" tabindex="-1"><a class="header-anchor" href="#email-template-for-contact-seller"><span>Email Template For Contact Seller</span></a></h4><p>The admin can set the email template to contact the seller on Seller’s Profile by clicking on <strong>Stores&gt;Configuration&gt;Marketplace Transactional Emails&gt;Ask Question to Seller Template.</strong></p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/transaction-email-1-2-956x1024.webp" alt="email-1"></p><h4 id="seller-s-feedback-page-1" tabindex="-1"><a class="header-anchor" href="#seller-s-feedback-page-1"><span>Seller’s Feedback Page</span></a></h4><p>Buyers can rate the seller according to his/her opinion under their profile with star rate vote and feedback message as shown below.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/mpmp19.png" alt="mpmp19"></p><h4 id="seller-s-location-page-1" tabindex="-1"><a class="header-anchor" href="#seller-s-location-page-1"><span>Seller’s Location Page</span></a></h4><p>By clicking on the seller location below the Seller’s shop name the buyer will be redirected to the seller’s location page.</p><p>From the seller’s location, page buyer can view the seller’s location on the map.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/m2mp44.png" alt="m2mp44"></p><h2 id="new-products" tabindex="-1"><a class="header-anchor" href="#new-products"><span>New Products</span></a></h2><p>Admin BackEnd Setting For Allowed Attribute Set &amp; Product Type For The Seller.</p><p>Well, the admin can set the functionality for not showing the select drop-down for selecting the attribute set and product type for adding products at the seller end as per the below cases-</p><h4 id="case-1" tabindex="-1"><a class="header-anchor" href="#case-1"><span><strong>Case 1</strong> :</span></a></h4><p>If the admin set only one “Attribute set” and one “Product type” then –</p><p>In this case, the seller will be directly taken to the “add product page” without being prompted to select the Attribute Set and the Product Type for the new product.</p><p>This will cut the selection of these two options for the sellers where the admin set only one Attribute set and only one Product type for the sellers.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/seller-product-settings-11-901x1024.webp" alt="settings"></p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/Screenshot-1-6.png" alt="Screenshot-1-6"></p><h4 id="case-2" tabindex="-1"><a class="header-anchor" href="#case-2"><span>Case 2 :</span></a></h4><p>If the admin set more than one “Attribute Set” and “Product Type” then – in this case:</p><p>The seller will have to first set the Attribute set and the Product type for the new product, and then the seller will be taken to the Add New Product form page.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/seller-product-settings-2.webp" alt="product setting
"></p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/Screenshot-2-6.png" alt="Screenshot-2-6"></p><h4 id="case-3" tabindex="-1"><a class="header-anchor" href="#case-3"><span>Case 3 :</span></a></h4><p>If the admin set only one “Attribute Set” and more than one “Product type” then – in this case:</p><p>The seller will first have to set the Product Type for the new product, and then the seller will be taken to the Add New Product form page.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/seller-product-settings-3-901x1024.webp" alt="product setting"></p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/Screenshot-from-2020-03-31-13-49-10.png" alt="Screenshot-from-2020-03-31-13-49-10"></p><h4 id="case-4" tabindex="-1"><a class="header-anchor" href="#case-4"><span><strong>Case 4</strong> :</span></a></h4><p>If the admin sets more than one “Attribute Set” and only one “Product type” then – in this case:</p><p>The seller will first have to set the Attribute Set for the new product, and then the seller will be taken to the Add New Product form page as per the below screenshot.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/seller-prduct-setting03-901x1024.webp" alt="setting-4"></p><p>The seller can add products from the seller’s end. Let us explain all the Product types one by one below.</p><h4 id="simple-product" tabindex="-1"><a class="header-anchor" href="#simple-product"><span><strong>Si</strong>mple Product</span></a></h4><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/www.devmage.com_11460_marketplace_product_create_Store-1.png" alt="www.devmage.com_11460_marketplace_product_create_Store-1"></p><p>After inserting Attribute Set and Product type, the below page will be open, in which you have to enter whole information about the product and save it. It’s all about adding a new product.</p><p>When the seller click on drafts, It add their product as a draft, It will not visible on frontend. It Will be list in draft products.</p><p>Short description, SKU, price, and special price information.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/06/add-new-draft-product-2-901x1024.webp" alt="add draft product"></p><p>Stock, availability, visibility, tax class, weight information and URL key.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2020/05/Screenshot-1.png" alt="Screenshot-1"></p><p>Meta title, meta keywords, meta description, set allowed product quantity, and product images.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/meta-information.png" alt="meta information"></p><p><a href="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/meta-information.png" target="_blank" rel="noopener noreferrer"></a></p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/related-product.png" alt="related product"></p><p>Downloadable product information, create configurations and select related products.</p><p>Select up-sell products.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/upsell-products.png" alt="upsell products"></p><p>Select cross-sell products.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/cross-sell-products.png" alt="cross-sell products"></p><p>The seller can make any image as the base image by clicking on that particular product image. Please refer to the image below.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/image-option.webp" alt="image-option"></p><h4 id="front-end-product-page" tabindex="-1"><a class="header-anchor" href="#front-end-product-page"><span>Front-end (Product Page):</span></a></h4><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/product-details.webp" alt="details"></p><p>The sellers can also add <strong>videos</strong> along with the <strong>product images</strong>.</p><p>The admin needs to enter his **YouTube account API Keys\xA0**in the admin backend panel by navigating to <strong>Stores</strong>-&gt;<strong>Configuration</strong>-&gt; <strong>Catalog</strong>-&gt;**Product Video.\xA0**</p><p>Here, the admin will enter his account(YouTube) API key and then save the configuration.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/product-videos-edited.webp" alt="product videos"></p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/product-attributes-edited.webp" alt="product attributes"></p><p>Now the sellers will be able to see the “<strong>Add Video</strong>” button on their add product page as shown below in the snapshot.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/add-video-button-edited.webp" alt="add video"></p><p>Clicking the “<strong>Add Video</strong>” button will bring up a section to add the video details. Here, the seller needs to fill in the required fields and save the configuration to add the video.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/add-video.webp" alt="add-video"></p><h4 id="downloadable-products" tabindex="-1"><a class="header-anchor" href="#downloadable-products"><span><strong>Downloadable Products</strong></span></a></h4><p>The seller can add Downloadable Product in Magento 2 Marketplace Extension.</p><p>Downloadable Products can be sold into Zip files such as software, e-books, images, music, or video.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/Screenshot-1-7.png" alt="Screenshot-1-7"></p><p>Adding up a downloadable product will create an additional field to enter the URL, as mentioned in the screenshot.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/downloadable-product-1200x796.webp" alt="downloadable product"></p><h4 id="virtual-product" tabindex="-1"><a class="header-anchor" href="#virtual-product"><span><strong>Virtual Product</strong></span></a></h4><p>The seller can add Virtual Product which does not have a physical presence.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/Screenshot-21.png" alt="Screenshot-21"></p><h4 id="configurable-product" tabindex="-1"><a class="header-anchor" href="#configurable-product"><span><strong>Configurable Product</strong></span></a></h4><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/Screenshot-2-7.png" alt="Screenshot-2-7"></p><p>Before creating a configurable product, the Seller needs to create the attribute for Configurable Products including Attribute Code, Attribute Label, Catalog Input Type, and Values Required.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/Screenshot-7-5.png" alt="multi vendor"></p><p>The seller can add a Configurable product as shown below. You must create an attribute for Configurable product.</p><p>After entering all the details about the product, the seller will click on “Create Configuration” and then the following pages will appear for the attributes code selection.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/add-video-button-1-edited.webp" alt="create configuration"></p><h4 id="select-attributes–" tabindex="-1"><a class="header-anchor" href="#select-attributes–"><span><strong>Select Attributes</strong>–</span></a></h4><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/select-attributes.webp" alt="select-sttributes"></p><p>Now, the seller will select the attributes value and then click on the Next button.</p><p><strong>Attributes Values</strong>– The seller will select attribute values from the check-box as per the image below.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/attribute-values.webp" alt="attribute-values"></p><p>Now, the seller will select options for bulk images, pricing, and quantity.</p><p><strong>Upload bulk images-</strong> Here, the seller can select an option like “Apply unique images by attribute to each SKU” and</p><p>Then select an attribute from the drop-down and upload image(s) for each attribute values.</p><p><strong>Bulk price and quantity-</strong> In the Pricing and Quantity, the seller will select the attribute from the drop-down and then enter different quantities for each attribute values.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/bulk-images-901x1024.webp" alt="bulk images"></p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/summary-edited.webp" alt="summary"></p><p>Now, the seller can review the product and then click on “Generate Products”.</p><p>After successful addition of the product, the seller can see it on the product add the page and then save that product.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/current-variation.webp" alt="current-variation"></p><h4 id="duplicate-product" tabindex="-1"><a class="header-anchor" href="#duplicate-product"><span>Duplicate Product</span></a></h4><p>A vendor can also create a duplicate copy of a product. A duplicate product can be created either at the time of editing or adding a new product.</p><p>To create a duplicate copy of an existing product, edit product and click <strong>Save &amp; Duplicate</strong> button.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/Screenshot-6-6.png" alt="Screenshot-6-6"></p><p>Once the duplicate product is created all the product information will be copied from the original product except the following:</p><ul><li>Status – It will be disabled.</li><li>SKU – Hyphen (-) sign with a # number will be added.</li><li>Stock – It will be zero.</li><li>Stock Availability – It will be out of stock.</li></ul><h2 id="my-product-list" tabindex="-1"><a class="header-anchor" href="#my-product-list"><span>My Product List</span></a></h2><p>Using this menu sellers can manage their products like they can edit their products, track their product sales, and can check their ordered stock quantity as per the screenshot.</p><p>There is a mass delete option by which sellers can delete a whole product at a time.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/my-product-list-1200x796.webp" alt="my product list"></p><p>The seller can use the Filter property in which products can be filtered according to Product Name, Status &amp; Date.</p><p>You can see this as below screenshot.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/products-filter-edited-1.webp" alt="filter"></p><h2 id="my-transaction-list" tabindex="-1"><a class="header-anchor" href="#my-transaction-list"><span>My Transaction List</span></a></h2><p>The seller can see their Transaction in this field. They can see whole statements(Total seller earning, Total Sales, and Commission\xA0 ) and total Payout.</p><p>They can also make a withdrawal request for the remaining payout. Clicking the “<strong>Make a Withdrawal</strong>” button will send an email to the admin that the seller wants to make a withdrawal.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/transaction-list.webp" alt="transaction-list"></p><p>The seller can also filter the transaction using Transaction id, Date, and view whole transaction details.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/transaction-list-view.webp" alt="transaction-list-view"></p><h2 id="earnings" tabindex="-1"><a class="header-anchor" href="#earnings"><span>Earnings</span></a></h2><p>The sellers can easily with accurate statistics able to see the store earning report. By navigating to the “Earnings” option on sidebar.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/mp-seller-dashboard-1.webp" alt="mp-seller-dashboard"></p><h3 id="timely-earnings-report-1" tabindex="-1"><a class="header-anchor" href="#timely-earnings-report-1"><span>Timely Earnings Report</span></a></h3><p>The seller can view the earning report of the store in terms of the day, month &amp; year wise.</p><h4 id="day-wise-report-1" tabindex="-1"><a class="header-anchor" href="#day-wise-report-1"><span>Day Wise Report</span></a></h4><p>The seller can view the earning report of the store day-wise.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2020/03/Earnings.png" alt="Earnings"></p><p>The seller can select the period as “Day”, and will enter the specific day to day period. A sales vs day wise graph will show you the sales day wise.</p><p>In addition, the seller can view the grid view of the total earnings day-wise.</p><h4 id="month-wise-report-1" tabindex="-1"><a class="header-anchor" href="#month-wise-report-1"><span>Month Wise Report</span></a></h4><p>The seller can view the earnings report of the store Month wise.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/Screenshot-2-5.png" alt="Screenshot-2-5"></p><p>The seller can select the period as “Month”, and will enter the specific starting and ending month period. A sales vs Month wise graph will show you the sales month wise.</p><p>In addition, the seller can view the grid view of the total earning month wise.</p><h4 id="year-wise-report-1" tabindex="-1"><a class="header-anchor" href="#year-wise-report-1"><span>Year Wise Report</span></a></h4><p>The seller can view the earnings report of the store Year wise.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/Screenshot-12-3.png" alt="Screenshot-12-3"></p><p>The seller can select the period as “Year”, will enter the specific starting and ending year period. A sales vs year-wise graph will show you the store earnings year wise.</p><p>In addition, the seller can view the grid view of the total earnings year-wise.</p><h2 id="multi-site-multi-store-multi-currency-–-magento-2-marketplace-extension" tabindex="-1"><a class="header-anchor" href="#multi-site-multi-store-multi-currency-–-magento-2-marketplace-extension"><span>Multi-site, Multi-store, Multi-Currency – Magento 2 Marketplace Extension</span></a></h2><h3 id="multi-store" tabindex="-1"><a class="header-anchor" href="#multi-store"><span>Multi-Store</span></a></h3><p>Setting up Multi store Magento 2 is one of the variable functionalities Magento 2 brings to store owners.</p><p>This feature allows you to create stores as many as you need only in a single configuration.</p><p>All stores that share the same domain and be set up as subdomains of the same domain.</p><p>It has entirely different domains, yet possibly shares the same backend for easier administration.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/how-to-setup-multiple-stores-magento-2-choose-new-store-view.png" alt="multi vendow marketplace"></p><h4 id="multi-site" tabindex="-1"><a class="header-anchor" href="#multi-site"><span>**Multi-Site\xA0**</span></a></h4><p>The website is the top-level container for sites,\xA0shipping methods,\xA0payment methods, and so on.</p><p>If you want to create completely separate sites that do not share the cart, shipping methods, and so on.</p><p>It is obligatory to create separate websites that will use the same domain or different domains.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/store-view-edited.webp" alt="Store-view"></p><h4 id="multi-currency" tabindex="-1"><a class="header-anchor" href="#multi-currency"><span><strong>Multi-currency.</strong></span></a></h4><p><strong>Configure Currency Magento 2</strong> to determine what currency customers will allow using when checking out your store.</p><p>The currency symbol will appear in product prices and sales documents such as orders and invoices. Most interestingly, store admins are able to customize their appearance if needed.</p><p>Moreover, with\xA0<strong>Magento 2 configuration</strong>, you can set more than 20 currency units of the corresponding countries in the world.</p><p>If your store accepts multiple currencies, Currency Chooser is available in the header of the storefront.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/currency-setup.webp" alt="currency-setup"></p><p>The customers can choose their preferred currency at the store front-end.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/mp-seller-dashboard-2.webp" alt="mp-seller-dashboard"></p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2019/11/multi-currency-selection-multi-vendor-marketplace-webkul.png" alt="multi vendor "></p><h2 id="my-order-history" tabindex="-1"><a class="header-anchor" href="#my-order-history"><span>My Order History</span></a></h2><p>Using this field seller can see their products order history in one shop. Order histories can filter by Order Id, Date, and Status.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/my-order-history.webp" alt="my-order-history"></p><p>After clicking the “Download All Invoice Slip &amp; Download All Shipping Slip”, a popup will appear where the seller can download the invoice and packing slips by entering “From” and “Until” date.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/download-slip-edited.webp" alt="Download slip"></p><p>After clicking on View Order, Order Details will display with Buyer information, Shipping address, shipping method, Billing address, Payment method, Items ordered as shown below.</p><p>Along with that, a seller can manage shipment, add the tracking number, the creation of credit memo, sending emails, printing of invoices, etc. Just by viewing order in ‘My order history’.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/order-details.webp" alt="order-details"></p><h4 id="refund" tabindex="-1"><a class="header-anchor" href="#refund"><span>Refund</span></a></h4><p>The seller can also refund the amount to his/her customers from the Magento 2 Marketplace Extension.</p><p>After creating the invoice, the seller will click on “Credit Memo” like the image below:</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/credit-memo-order.webp" alt="credit-memo-order"></p><p>The seller can update the quantity for the refund and can also add the adjustment fees.</p><p>You can check the below image for a better understanding:</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/credit-memo-slip-1200x796.webp" alt="credit-memo-slip"></p><h2 id="customer" tabindex="-1"><a class="header-anchor" href="#customer"><span>Customer</span></a></h2><p>Under this section,\xA0 the seller will be able to view all of his customers and can see the order placed by the customers as well.</p><p>The seller can also view his\xA0customer’s details like- Name, Email, Contact Number, Gender, Address, Base Total, and Order Number.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/my-customer-edited.webp" alt="my-customer"></p><h2 id="customer-review" tabindex="-1"><a class="header-anchor" href="#customer-review"><span>Customer Review</span></a></h2><p>The seller will be able to view all the review and ratings given by the customers.</p><p>The vendor can check the price, value, quality ratings along with the feed summary, review, date and the customer name with the status of the review as well.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/Marketplace-Review-1-1.png" alt="Multi Vendor Marketplace Review"></p><h2 id="manage-print-pdf-header-info" tabindex="-1"><a class="header-anchor" href="#manage-print-pdf-header-info"><span>Manage Print PDF header Info</span></a></h2><p>Here seller will enter Invoice and Packing Slip Address/VAT/Tax Information which will appear in the header of PDF files.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/manage-print-pdf-edited.webp" alt="manage print pdf"></p><h2 id="marketplace-dashboard" tabindex="-1"><a class="header-anchor" href="#marketplace-dashboard"><span>Marketplace Dashboard</span></a></h2><p>Using seller dashboard seller can track his income, 5 top selling products, total sales over time, total payout, and the remaining amount that is left to be paid out.</p><p>Also, the seller can track his paid commission, orders and can filter the results using year, month, week and day using an interactive map.</p><p>Seller will be able to see his top-selling category list. Similarly, the seller can see his sales statistics</p><p>Such as total sales over time,orders over time , average order value over time, as a graph and can filter the results using the year, month, week, and day shown in below image –</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/06/marketplace-vendor-dashboard.webp" alt="multivendor-marketplace-dashboard"></p><p>Using seller dashboard seller can track his latest order, notifications, price rating, value rating,quality rating, Latest comment and reviews in their Activities section.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/06/marketplace-vendor-dashboard-reports-3.webp" alt="marketplace-vendor-dashboard-reports "></p><p>If Seller has any doubts or query then, they can frequently ask the questions or doubts to the admin by clicking on Ask Question to Admin button.</p><p>This is a way of communication between Seller and Admin for Seller’s query.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/ask-question-to-admin-edited.webp" alt="ask question to admin"></p><h4 id="admin-news" tabindex="-1"><a class="header-anchor" href="#admin-news"><span>Admin News</span></a></h4><p>The seller can see the news listing published by admin in the “<strong>Admin News</strong>” as shown in below image –</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/admin-news-1.webp" alt="admin-news"></p><h2 id="seller-order-notification-mail-template" tabindex="-1"><a class="header-anchor" href="#seller-order-notification-mail-template"><span>Seller Order Notification Mail Template</span></a></h2><p>In the Magento 2 Marketplace Extension, if an order is placed and its invoice is created then the seller will receive product sold notification mail with their product details.</p><p>For example, if an order is placed with three products (A, B, C) of Seller (x,y,z) respectively.</p><p>So when order invoice will be created then sellers (X, Y, Z) will receive an email for their products (A, B, C respectively) with order details.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/email-seller-template.png" alt="Multi Vendor Order"></p><h2 id="marketplace-admin-management" tabindex="-1"><a class="header-anchor" href="#marketplace-admin-management"><span>Marketplace Admin Management</span></a></h2><p>After the successful setup of the Magento 2 Marketplace Extension, the admin will be able to see “Marketplace Management” as per the below screen.</p><p>The admin can also view the notification count for new seller requests, add or edit seller product and new feedback.</p><p>The admin can also view the notification count for new seller requests, add or edit seller product and new feedback.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/mp-seller-flag-2-1200x796.webp" alt="Admin dashboard"></p><p>Please refer from the screenshot below:</p><h3 id="manage-products" tabindex="-1"><a class="header-anchor" href="#manage-products"><span>Manage Products</span></a></h3><p>This menu is responsible for managing Seller’s Product from Marketplace configuration panel (<strong>Store &gt; Settings &gt; Configuration</strong>).</p><p>Product approval is required then, in this case, every product added by seller needs to be approved by admin.</p><p>Product approval will happen from the Manage Product menu as per the screenshot. There is also a Deny and remark option by which admin can deny and remark the Seller’s product for a valid reason.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/06/admin-remark.webp" alt="admin-remark"></p><p>On clicking on the Product image, admin can see enlarged image for the better view and at the bottom, there is a link to view product detail.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/go-to-details-page.webp" alt="deatls page"></p><p>The admin can give remark to any pending product by clicking on the Remark button as shown in image below –</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/06/remark-to-product-1200x455.webp" alt="remark to product"></p><p>The admin can deny any approved product by clicking on the Deny button for a particular reason.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/deny-the-product-edited.webp" alt="deny product"></p><h3 id="manage-seller" tabindex="-1"><a class="header-anchor" href="#manage-seller"><span>Manage Seller</span></a></h3><p>This menu is responsible for Seller Management from marketplace configuration panel (<strong>Store &gt; Settings &gt; Configuration</strong>).</p><p>If partner approval is required then, in this case, the admin needs to set the status of the seller:</p><ol><li>Disapprove- Admin can disapprove the seller.</li><li>Approve- Admin can approve the seller.</li><li>Processing- Admin can set the status of the seller profile from pending to processing.</li></ol><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/manage-seller-2-1200x520.webp" alt="manage seller"></p><h4 id="view-seller-s-order" tabindex="-1"><a class="header-anchor" href="#view-seller-s-order"><span><strong>View Seller’s Order-</strong></span></a></h4><p>When the admin clicks on “Order” then all the orders of that seller will be displayed. Admin can also see the amount left to be paid to the seller.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/manage-seller-order.webp" alt="manage-seller-order
"></p><p>In the Magento 2 Marketplace Extension, the admin can deny any seller by clicking on the Deny Button and entering the reason.</p><p>To clear out the message admin can click the reset button.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/deny-seller-edited-1.webp" alt="deny-seller"></p><h4 id="view-edit-seller-s-information" tabindex="-1"><a class="header-anchor" href="#view-edit-seller-s-information"><span><strong>View/Edit Seller’s Information-</strong></span></a></h4><p>Click the Marketplace Manage seller menu and select the seller to open the below page with the seller information. Here, admin can edit any detail and then save it.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/M2MP1.png" alt="M2MP1"></p><p>Admin can see Payment details entered by a Seller during account creation. These payment details will be used by the admin to pay the sellers.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/M2MP2.png" alt="M2MP2"></p><p>The admin can set the commission in percentage for any particular seller and can also see Total Sale, Total Seller Sale, Total Admin Sale.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/M2MP3.png" alt="M2MP3"></p><p>The admin can assign categories to a seller by going to the Assign Category option as visible in the screenshot below. The seller can now add products and select only the assigned categories.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/M2MP4.png" alt="M2MP4"></p><p>When the admin needs to assign any product or mass assign products to any particular seller, the admin will click the menu item “Product Assignment”.</p><p>Here the admin finds a complete list of products in the catalog.</p><p>Admin checks the Ids of the products that are to be assigned to the seller and click the save customer button after that to assign the products to the seller.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/M2Mp5.png" alt="M2Mp5"></p><p>The admin can assign attribute set to the vendor as per the below image.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/M2mp7.png" alt="M2mp7"></p><p>Using this field admin can remove any seller from the Marketplace and make him a normal customer.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/M2Mp6.png" alt="M2Mp6"></p><h4 id="assign-seller-to-the-product" tabindex="-1"><a class="header-anchor" href="#assign-seller-to-the-product"><span><strong>Assign Seller to the Product</strong></span></a></h4><p>Just like the admin assigns product to the seller, in Magento 2 Marketplace Extension, the admin also assign sellers to products.</p><p>For this, the admin opens the product in edit mode and then select the seller to assign the product:</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/webkul_magento2_multi_vendor_mp_admin_assigns_seller_to_product.jpg" alt="webkul_magento2_multi_vendor_mp_admin_assigns_seller_to_product"></p><p>**Note: **This functionality does not work for the products which are already assigned to their respective sellers.</p><p>Likewise, for doing this, first, the admin needs to un-assign that product from the edit seller page to which it is assigned.</p><h2 id="admin-product-list" tabindex="-1"><a class="header-anchor" href="#admin-product-list"><span>Admin Product List\xA0</span></a></h2><p>Here the admin can see the seller’s name in the product list.</p><p><strong>Note:</strong> \xA0If products are already created by the admin or sellers then execute given command to assign seller or admin id on products.</p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">php bin/magento assign:mp:product</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/06/admin-remark-3.webp" alt="admin manage seller product"></p><h2 id="manage-commission" tabindex="-1"><a class="header-anchor" href="#manage-commission"><span>Manage Commission</span></a></h2><p>Here in the Magento 2 Marketplace Extension, admin can view details like Seller ID, Commission percentage, Total Sales, Received Amount, Remaining Amount, Commission value and Last paid.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/manage-commision-edited.webp" alt="manage-commission
"></p><h4 id="seller-transaction" tabindex="-1"><a class="header-anchor" href="#seller-transaction"><span>Seller Transaction</span></a></h4><p>Here, the admin can view the transaction detail which comes after the admin pays the seller.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/seller-transcation-edited.webp" alt="seller-transaction
"></p><h4 id="manage-feedback" tabindex="-1"><a class="header-anchor" href="#manage-feedback"><span>Manage Feedback</span></a></h4><p>This menu is responsible for all the reviews. Admin can approve, unapproved, and delete the reviews. Unapproved or deleted.</p><p>Reviews will not appear in Seller’s account. Admin can also see the ratings for price, value, and quality in terms of the star.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/manage-feedback-edited.webp" alt="manage-feedback"></p><h2 id="manage-news" tabindex="-1"><a class="header-anchor" href="#manage-news"><span>Manage News</span></a></h2><p>This menu is responsible for all the news that are published by admin. These news will visible to all sellers.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/06/admin-publish-news.webp" alt="admin-publish-news"></p><p>Here, the admin can also add the news by clicking on <strong>“New News”</strong> and It will be visible to all sellers in their admin news section.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/06/add-news-edited.webp" alt="add-news"></p><h2 id="when-admin-set-seller-profile-to-no" tabindex="-1"><a class="header-anchor" href="#when-admin-set-seller-profile-to-no"><span>When Admin set seller Profile to No</span></a></h2><p>When the admin set the seller profile page setting for “<strong>Show Seller Profile</strong>” to “<strong>No”</strong> at the back end.</p><p>Under <strong>Stores&gt;Configuration&gt;Marketplace &gt;Seller profile Page Settings</strong> as shown below, many pages are affected by this setting.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/seller-setting-no-edited.webp" alt="display-seller-profile"></p><h4 id="landing-page-–-magento-2-marketplace-extension" tabindex="-1"><a class="header-anchor" href="#landing-page-–-magento-2-marketplace-extension"><span>Landing Page – Magento 2 Marketplace Extension</span></a></h4><p>Seller information is hidden from the marketplace landing page as shown below.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/no-product0visible-901x1024.webp" alt="No product visible"></p><p>On the product page, the seller information which is visible to the customers is hidden as shown below in the screenshot.</p><h4 id="product-page" tabindex="-1"><a class="header-anchor" href="#product-page"><span>Product Page</span></a></h4><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/product-details-1-edited.webp" alt="product-details"></p><h4 id="seller-order-history-page" tabindex="-1"><a class="header-anchor" href="#seller-order-history-page"><span>Seller Order History Page</span></a></h4><p>On ** My Order History page**, the buyer information hides from the seller as shown below.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/06/my-order-history.webp" alt="order-history"></p><p>The buyer information also hides at the <strong>View Order Details</strong> page as shown below in the screenshot.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/06/view-order-details-1200x796.webp" alt="order-details"></p><p>Now, you can see the buyer details are hidden for the <strong>Shipment Tab</strong> as shown below in the screenshot.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/06/new-shipment-901x1024.webp" alt="new-shipment"></p><p>Furthermore, the <strong>Packaging Slip</strong> downloaded as a PDF does not have any buyer details on it as shown below in the screenshot.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/06/packing-slip-shipment.webp" alt="packing-shipment-slip"></p><h3 id="invoice-and-credit-memo" tabindex="-1"><a class="header-anchor" href="#invoice-and-credit-memo"><span>Invoice and Credit Memo</span></a></h3><h4 id="invoice" tabindex="-1"><a class="header-anchor" href="#invoice"><span><strong>Invoice</strong>\xA0</span></a></h4><p>Now, the buyer information will hide on the **View Invoice Details **page of the seller as shown below.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/06/invoice-details-1.webp" alt="Invoice details "></p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/invoice-ss-2.webp" alt="invoice-information"></p><h4 id="credit-memo" tabindex="-1"><a class="header-anchor" href="#credit-memo"><span><strong>Credit Memo</strong>\xA0</span></a></h4><p>However, buyer information is hidden at the <strong>Credit Memo Generation</strong> page .</p><p>Additionally, on the <strong>View Credit Memo</strong> details page, the buyer information is hidden as per the below screenshot.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/06/new-credit-memo-1.webp" alt="new-credit-memo"></p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/06/new-credit-memo-2.webp" alt="credit-memo-marketpalce"></p><p>Additionally, the Buyer information is hidden from the downloaded <strong>Credit Memo</strong> pdf as shown below –</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/06/credit-memo-shipment.webp" alt="credit-memo-packing-slip"></p><h2 id="how-to-use-advanced-pricing-in-multi-vendor-marketplace" tabindex="-1"><a class="header-anchor" href="#how-to-use-advanced-pricing-in-multi-vendor-marketplace"><span>How to Use Advanced Pricing in Multi-Vendor Marketplace?</span></a></h2><p>Advanced pricing can be said as the special price offered to a specific group of customers. Also, advanced pricing can be implemented on simple, virtual, downloadable, and bundle products.</p><p>And Advanced pricing data is synchronized with product pages. For example, if you update a tier price quantity, the system updates the value on the product page.</p><ul><li>On the admin end, the advance pricing can be set on the product. For this,</li><li>The admin needs to open the product in edit mode.</li><li>After which under Price we have Advanced Price, where we can set <ul><li>Special Price(along with the date\xA0of validity)</li><li>Tier Price</li></ul></li></ul><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/05/advance-pricing-edited.webp" alt="advance-pricing"></p><h2 id="how-to-make-tier-price-visible-on-seller-end" tabindex="-1"><a class="header-anchor" href="#how-to-make-tier-price-visible-on-seller-end"><span>How To Make Tier Price Visible On Seller End?</span></a></h2><p>Certainly, the Tier Price is a major component of Advance Pricing which gives the customer the advantage of receiving a discount on the basis of the quantity purchased.</p><p>That is, you offer a quantity discount on a product listing or product page in the storefront. However, the discount can be applied to a specific store view or customer group.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/06/tier-price-frontend-image-1.webp" alt="tier-price-frontend
"></p><p><strong>Extended Functionality-</strong> The Magento 2 Marketplace Extension is having an additional feature.</p><p>That enables the seller to have a facility to set tier price for the product for a specific group of people too.</p><p>Moreover, this achieves by<a href="https://store.webkul.com/Magento2-Marketplace-Custom-Attribute.html" target="_blank" rel="noopener noreferrer"> Magento 2 Custom Attribute Marketplace Add-on</a>, we can simply go to **Custom Attributes **in the admin panel.</p><p>Also, the admin can select the ‘tier_price’ attribute and under the <strong>Action</strong> drop-down, click on ‘<strong>Show In Front</strong>.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/06/tier-price-image-1-1-1200x528.webp" alt="tier price "></p><p>Now, the attribute <strong>Tier Price</strong> could be seen on seller front when we open the product in edit mode.</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2015/12/add-advance-pricing.webp" alt="add-advance-pricing"></p><p><strong>Note-</strong> In order, to have the functionality of Tier Pricing in Seller end you must have the add-on, Custom Attribute Marketplace Add-on.</p><h2 id="support" tabindex="-1"><a class="header-anchor" href="#support"><span>Support</span></a></h2><p>Therefore, In conclusion, that’s all for the Magento 2 Marketplace Extension.</p><p>For any queries or doubts, you can reach out to us by dropping an email at\xA0<a href="/cdn-cgi/l/email-protection" target="_blank" rel="noopener noreferrer">[email\xA0protected]</a>\xA0or raising a query at our\xA0<a href="https://webkul.uvdesk.com/en/customer/create-ticket/" target="_blank" rel="noopener noreferrer">HelpDesk</a>\xA0system.</p><p>For more such kinds of extensions, you can view our <a href="https://store.webkul.com/Magento-2.html" target="_blank" rel="noopener noreferrer">Magento 2 Extensions</a>.</p><p>Current Product Version - 5.0.2</p><p>Supported Framework Version - Magento 2.0.x, 2.1.x, 2.2.x,2.3.x, 2.4.x</p><p><img src="https://cdnblog.webkul.com/blog/wp-content/uploads/2024/08/nishad-2.webp" alt="author-thumb"></p><p><a href="https://webkul.com/blog/author/nishad-bhan981/" target="_blank" rel="noopener noreferrer">Nishad Bhan 7 Badges</a></p><p>Nishad Bhan excels in analyzing eCommerce processes on the Magento platform, optimizing workflows, and delivering strategic solutions. Expertise ensures seamless platform integration, driving digital innovation and aligning technology with business objectives for growth.</p><ul><li>7 May, 2026 Updated by - Udayveer Singh</li><li>26 Feb, 2026 Updated by - Udayveer Singh</li></ul><p>View More</p><p>Blog Version - Magento 2.0.x, 2.1.x, 2.2.x,2.3.x, 2.4.x</p><ul><li>Version Magento 2.0.x, 2.1.x, 2.2.x,2.3.x, 2.4.x</li><li>Version 2.0.x, 2.1.x, 2.2.x, 2.3.x, 2.4.x</li></ul>`,1050)]])}var s=r(a,[[`render`,o]]);export{i as _pageData,s as default};